                    model_pred = self.scheduler.get_velocity(latents_gt, noise_ori, t)
                    output = self.scheduler.step(model_pred, t, latent_model_input, **extra_step_kwargs)
                    latent_prev_gt_noise, x0_est_gt_noise = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)



                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
