                    #特征保存 输入特征保存
                    latents_input_dir = os.path.join(cur_img_idx_dir,"latents_input")
                    os.makedirs(latents_input_dir,exist_ok=True)
                    latents_cur_input = latents[num_image]
                    latent_feature_num = latents_cur_input.shape[1]
                    for i in range(latent_feature_num):
                        latent_feature_idx = latents_cur_input[0,[i],...]     #当前的特征idx
