                    latents_cur_input_decoders = latents_cur_input_decoders * 0.5 + 0.5
                    latents_cur_input_decoders_img = (latents_cur_input_decoders[0].permute(1,2,0)*255.0).detach().cpu().numpy().astype(np.uint8)
