                    #         return_dict=False,
                    #         # num_scales=1,
                    #     )[0]
                    if isinstance(noise_pred,List):
                        noise_pred=noise_pred[-1]
                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latent_prev, x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est
                    #特征保存 前一时刻的特征保存
                    latents[num_image] = latent_prev
                    latents_prev_dir = os.path.join(cur_img_idx_dir,"latents_prev")
