                    os.makedirs(latents_predX0_dir,exist_ok=True)
                    latents_X0_pred = x0_est
                    latent_feature_num = latents_X0_pred.shape[1]
                    for i in range(latent_feature_num):
                        latent_feature_idx = latents_X0_pred[0,[i],...]     #当前的特征idx
                        # #归一化操作
                        # latent_feature_idx = (latent_feature_idx - latent_feature_idx.min())/(latent_feature_idx.max()-latent_feature_idx.min())
                        # color_latent = (latent_feature_idx.permute(1, 2, 0) * 255.0).cpu().contiguous().detach().numpy().astype(
                        #     np.uint8)
                        # color_latent = cv2.applyColorMap(color_latent, cv2.COLORMAP_JET)
                        # color_latent_path = os.path.join(latents_predX0_dir,f"latent_{i:05d}.png")
                        # cv2.imwrite(color_latent_path,color_latent)
                        # time_out_dict[f"ori_sampling_latents_pred_X0_{i:05d}.png"] = color_latent
                        time_out_dict[f"ori_sampling_latents_pred_X0_{i:05d}.png"] = latent_feature_idx
                        ccc=0

                    #转到RGB
                    latents_X0_pred_decoders = self.vae.decode(latents_X0_pred / self.vae.config.scaling_factor, return_dict=False, num_scales=1,scale_factors=[scale_recon])[0]
