                    latents_X0_pred_decoders = latents_X0_pred_decoders * 0.5 + 0.5
                    latents_X0_pred_decoders_img = (latents_X0_pred_decoders[0].permute(1,2,0)*255.0).detach().cpu().numpy().astype(np.uint8)
                    img_gt_dir = os.path.join(cur_img_idx_dir,"latents_X0_pred_decoders_img")
