from diffusers.models.unet_2d_condition import UNet2DMultiScaleConditionModel


#利用时间约束的网络
class StableVSRCrossTimePipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetTimeModel, List[ControlNetTimeModel], Tuple[ControlNetTimeModel], MultiControlTimeNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlTimeNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlTimeNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlTimeNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetTimeModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetTimeModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlTimeNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlTimeNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetTimeModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetTimeModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlTimeNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlTimeNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlTimeNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None,
            lambda_step=None,                       #参与修正的步数
            GT_images=None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlTimeNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlTimeNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetTimeModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetTimeModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlTimeNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        #当前帧的前一时刻
        latents_tprecfcur = [None for _ in latents]
        #前一帧的前一时刻
        latents_tprecfpre = [None for _ in latents]

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetTimeModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                #当前时刻100个 前一时刻99个
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据
                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                        #前一帧或者后一帧的当前时刻 warped_prev_est
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        if i == 0:
                            down_block_res_samples = None
                            mid_block_res_sample = None
                        else:
                            X0_pred_prevtimes = latents_tprecfcur[num_image]
                            X0_pred_prevtimes = self.vae.decode(X0_pred_prevtimes / self.vae.config.scaling_factor, return_dict=False)[
                                0]  # convert x0_est to RGB

                            down_block_res_samples, mid_block_res_sample = controlnet(
                                control_model_input,
                                t,
                                encoder_hidden_states=controlnet_prompt_embeds,
                                controlnet_cond=warped_prev_est,
                                conditioning_scale=cond_scale,
                                controlnettprefcur_cond=X0_pred_prevtimes,  # 当前帧的前一时刻
                                # controlnettprefpre_cond=controlnet_image_tprefpre,  # 前一帧的前一时刻
                                timestepprev=timesteps[i - 1],  # 前一时刻
                                # class_labels = noise_level,
                                guess_mode=guess_mode,
                                return_dict=False,
                                timestep_cond=None
                            )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])
                    else:
                        if i ==0:
                            # predict with Temporal Conditioning Module
                            down_block_res_samples, mid_block_res_sample = self.controlnet(
                                control_model_input,
                                t,
                                encoder_hidden_states=controlnet_prompt_embeds,
                                controlnet_cond=warped_prev_est,
                                conditioning_scale=cond_scale,
                                # class_labels = noise_level,
                                guess_mode=guess_mode,
                                return_dict=False,
                                timestep_cond=None
                            )
                        else:
                            X0_pred_prevtimes = latents_tprecfcur[num_image]
                            X0_pred_prevtimes = self.vae.decode(X0_pred_prevtimes / self.vae.config.scaling_factor, return_dict=False)[
                                0]  # convert x0_est to RGB
                            X0_pred_prevframetime = latents_tprecfcur[num_image-1]
                            X0_pred_prevframetime = self.vae.decode(X0_pred_prevframetime / self.vae.config.scaling_factor, return_dict=False)[
                                0]  # convert x0_est to RGB
                            warped_prev_est = of.flow_warp(X0_pred_prevframetime, flows[num_image - 1],
                                                           interp_mode=interp_mode)
                            down_block_res_samples, mid_block_res_sample = controlnet(
                                control_model_input,
                                t,
                                encoder_hidden_states=controlnet_prompt_embeds,
                                controlnet_cond=warped_prev_est,
                                conditioning_scale=cond_scale,
                                controlnettprefcur_cond=X0_pred_prevtimes,  # 当前帧的前一时刻
                                controlnettprefpre_cond=X0_pred_prevframetime,  # 前一帧的前一时刻
                                timestepprev=timesteps[i-1],  # 前一时刻
                                # class_labels = noise_level,
                                guess_mode=guess_mode,
                                return_dict=False,
                                timestep_cond=None
                            )



                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # # # # down_block_res_samples = None
                    # if down_block_res_samples is not None:
                    #     for idx,data in enumerate(down_block_res_samples):
                    #         down_block_res_samples[idx] = torch.zeros_like(data)
                    # if mid_block_res_sample is not None:
                    #     mid_block_res_sample = torch.zeros_like(mid_block_res_sample)
                    #
                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    #这一次预测之后保存结果 x0_est 是 fpretcur
                    # latents_tprecfcur[num_image] = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                    #         0]
                    latents_tprecfcur[num_image] = x0_est
                    ccc=0

                    # if num_image != 0:  # if it's not the first image
                    #     latents_tprecfpre[num_image] = warped_prev_est
                    # else:
                    #     x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                    #         0]  # convert x0_est to RGB
                    #     warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                    #                                    interp_mode=interp_mode)  # warp it to current frame
                    #     latents_tprecfpre[num_image] = warped_prev_est


                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


class StableVSRFusionPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # # # # down_block_res_samples = None
                    # if down_block_res_samples is not None:
                    #     for idx,data in enumerate(down_block_res_samples):
                    #         down_block_res_samples[idx] = torch.zeros_like(data)
                    # if mid_block_res_sample is not None:
                    #     mid_block_res_sample = torch.zeros_like(mid_block_res_sample)
                    #
                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)

#
class StableVSRFusionLQPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # # # # down_block_res_samples = None
                    # if down_block_res_samples is not None:
                    #     for idx,data in enumerate(down_block_res_samples):
                    #         down_block_res_samples[idx] = torch.zeros_like(data)
                    # if mid_block_res_sample is not None:
                    #     mid_block_res_sample = torch.zeros_like(mid_block_res_sample)
                    #
                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。

                    # upscaleed lq upscaled_lq_cur
                    down_block_res_samples_lq, mid_block_res_sample_lq = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=upscaled_images[num_image],
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                    down_block_additional_residuals_in = [sample.to(self.unet.device) for sample in down_block_res_samples_lq]
                    down_block_additionals =[down_block_additional_residuals_in]
                    mid_block_additional_residuals_in = [mid_block_res_sample_lq]
                    if mid_block_res_sample is not None:
                        mid_block_additional_residuals_in.append(mid_block_res_sample)
                    if down_block_res_samples is not None:
                        down_block_additionals.append([sample.to(self.unet.device) for sample in down_block_res_samples])

                    # Predict the noise residual
                    # 利用 当前时刻的输入 以及获得的时间上的特征残差进行预测当前时刻的噪声残差
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals= down_block_additionals,
                        mid_block_additional_residual=mid_block_additional_residuals_in,
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)




# 修改生成策略 对所有帧对齐之后再作为时间引导
class StableVSRWrapPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # # # # down_block_res_samples = None
                    # if down_block_res_samples is not None:
                    #     for idx,data in enumerate(down_block_res_samples):
                    #         down_block_res_samples[idx] = torch.zeros_like(data)
                    # if mid_block_res_sample is not None:
                    #     mid_block_res_sample = torch.zeros_like(mid_block_res_sample)
                    #
                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


'''
进行随机约束
'''
class StableVSRRandomPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None,
            batch_len = 10,
            ratio = 0.3
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                # 将 图像 cat 成之前的样子
                # batch_size = 10
                # ratio = 0.3
                stack_images =self.stack_images(images,batch_size=batch_len)
                len_stack = len(stack_images)
                step = math.floor(ratio*len_stack)    #P 越大 效果越差
                choices_indexs = sorted(np.random.choice(len_stack, step ,replace=False))
                for num_batch,batch_data in enumerate(stack_images):
                    len_batch = len(batch_data)
                    if num_batch in choices_indexs:
                        start_idx = num_batch * batch_size
                        latent_model_input = torch.cat([latents[start_idx:start_idx + len_batch]] * 2) if do_classifier_free_guidance else \
                            latents[start_idx:start_idx + len_batch]
                        latent_model_input = torch.cat(latent_model_input)
                        latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                        image = images[start_idx:start_idx + len_batch]
                        image = torch.cat(image)
                        # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                        latent_model_input = torch.cat([latent_model_input, image], dim=1)
                        # predict the noise residual
                        # 使用 UNet 预测噪声残差（noise_pred）。
                        # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                        noise_pred = self.unet(
                            latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                            t,  # 当前的时间步 t
                            encoder_hidden_states=prompt_embeds.repeat(len(latent_model_input),1,1),  # prompt_embeds 文本编码的特征向量
                            # class_labels = noise_level,
                            cross_attention_kwargs=cross_attention_kwargs,  # None
                            # down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                            # mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                            return_dict=False,
                        )[0]

                        # perform guidance
                        if do_classifier_free_guidance:
                            noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                            noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                        # compute the previous noisy sample x_t -> x_t-1
                        # 更新潜变量：
                        #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                        #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                        latent_tmp = torch.cat(latents[start_idx:start_idx + len_batch])
                        output = self.scheduler.step(noise_pred, t, latent_tmp, **extra_step_kwargs)
                        latents_tt,x0_est_tt = output.prev_sample, output.pred_original_sample
                        for i_idx in range(len(batch_data)):
                            latents[start_idx + i_idx] = latents_tt[[i_idx]]   # x_t-1, x0_est
                            ccc=0
                            # i = start_idx + i
                            # call the callback, if provided
                            # 进度条和回调函数：
                            #   在每个时间步结束时更新进度条。
                            #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                        if i == len(timesteps) - 1 or (
                                (i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                            progress_bar.update()
                            if callback is not None and i % callback_steps == 0:
                                callback(i, t, latents)
                    else:
                        for num_image, data in enumerate(batch_data):  # 遍历图像帧
                            gloabl_num_image = num_batch * batch_size + num_image
                            image = data.unsqueeze(0)  # 图像数据

                            # compute Temporal Texture Guidance
                            # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                            if num_image != 0:  # if it's not the first image
                                x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                                    0]  # convert x0_est to RGB
                                warped_prev_est = of.flow_warp(x0_est, flows[gloabl_num_image - 1],
                                                               interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                            # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                            # expand the latents if we are doing classifier free guidance
                            latent_model_input = torch.cat([latents[gloabl_num_image]] * 2) if do_classifier_free_guidance else \
                            latents[gloabl_num_image]
                            latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                            # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                            latent_model_input = torch.cat([latent_model_input, image], dim=1)

                            # controlnet(s) inference
                            # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                            if guess_mode and do_classifier_free_guidance:
                                # Infer ControlNet only for the conditional batch.
                                control_model_input = latents
                                control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                                controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                            else:
                                control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                                controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                            # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                            if isinstance(controlnet_keep[i], list):
                                cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                            else:
                                controlnet_cond_scale = controlnet_conditioning_scale
                                if isinstance(controlnet_cond_scale, list):
                                    controlnet_cond_scale = controlnet_cond_scale[0]
                                cond_scale = controlnet_cond_scale * controlnet_keep[i]

                            # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                            if num_image == 0:
                                # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                                down_block_res_samples = None
                                mid_block_res_sample = None
                            else:
                                # predict with Temporal Conditioning Module
                                down_block_res_samples, mid_block_res_sample = self.controlnet(
                                    control_model_input,
                                    t,
                                    encoder_hidden_states=controlnet_prompt_embeds,
                                    controlnet_cond=warped_prev_est,
                                    conditioning_scale=cond_scale,
                                    # class_labels = noise_level,
                                    guess_mode=guess_mode,
                                    return_dict=False,
                                    timestep_cond=None
                                )

                                if guess_mode and do_classifier_free_guidance:
                                    # Infered ControlNet only for the conditional batch.
                                    # To apply the output of ControlNet to both the unconditional and conditional batches,
                                    # add 0 to the unconditional batch to keep it unchanged.
                                    down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                              down_block_res_samples]
                                    mid_block_res_sample = torch.cat(
                                        [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                            # predict the noise residual
                            # 使用 UNet 预测噪声残差（noise_pred）。
                            # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                            noise_pred = self.unet(
                                latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                                t,  # 当前的时间步 t
                                encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                                # class_labels = noise_level,
                                cross_attention_kwargs=cross_attention_kwargs,  # None
                                down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                                mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                                return_dict=False,
                            )[0]

                            # perform guidance
                            if do_classifier_free_guidance:
                                noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                                noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                            # compute the previous noisy sample x_t -> x_t-1
                            # 更新潜变量：
                            #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                            #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                            output = self.scheduler.step(noise_pred, t, latents[gloabl_num_image], **extra_step_kwargs)
                            latents[gloabl_num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                            # call the callback, if provided
                            # 进度条和回调函数：
                            #   在每个时间步结束时更新进度条。
                            #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                            # i = gloabl_num_image
                        if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                            progress_bar.update()
                            if callback is not None and i % callback_steps == 0:
                                callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)
    #将输入的图像stack成一个大图
    def stack_images(self,images,batch_size=5):
        f = len(images)
        if f > batch_size:
            images_cat = [torch.cat(images[i:i + batch_size], dim=0) for i in range(0, f, batch_size)]
            return images_cat
        else:
            return [torch.cat(images, dim=0)]

'''
进行有重叠的随机约束
'''
class StableVSROverlapRandomPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None,
            batch_len: int = 1,
            ratio: float = 1.0,
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                warped_images,unwarpd_images,warp_idxs,unwarp_idxs = self.process_images(images,ratio,batch_len)
                # 处理为对齐的数据
                warp_start_idx = 0
                if unwarpd_images is not None:
                    for num_batch,unwarp_data in enumerate(unwarpd_images):
                        start_idx = unwarp_idxs[warp_start_idx]
                        batch_ll = len(unwarp_data)

                        latent_model_input = torch.cat(
                            [latents[start_idx:start_idx + batch_ll]] * 2) if do_classifier_free_guidance else \
                            latents[start_idx:start_idx + batch_ll]
                        latent_model_input = torch.cat(latent_model_input)
                        latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                        image = images[start_idx:start_idx + batch_ll]
                        image = torch.cat(image)
                        # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                        latent_model_input = torch.cat([latent_model_input, image], dim=1)
                        # predict the noise residual
                        # 使用 UNet 预测噪声残差（noise_pred）。
                        # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                        noise_pred = self.unet(
                            latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                            t,  # 当前的时间步 t
                            encoder_hidden_states=prompt_embeds.repeat(len(latent_model_input), 1, 1),
                            # prompt_embeds 文本编码的特征向量
                            # class_labels = noise_level,
                            cross_attention_kwargs=cross_attention_kwargs,  # None
                            # down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                            # mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                            return_dict=False,
                        )[0]

                        # perform guidance
                        if do_classifier_free_guidance:
                            noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                            noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                        # compute the previous noisy sample x_t -> x_t-1
                        # 更新潜变量：
                        #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                        #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                        latent_tmp = torch.cat(latents[start_idx:start_idx + batch_size])
                        output = self.scheduler.step(noise_pred, t, latent_tmp, **extra_step_kwargs)
                        latents_tt, x0_est_tt = output.prev_sample, output.pred_original_sample
                        for i_idx in range(len(unwarp_data)):
                            latents[start_idx + i_idx] = latents_tt[[i_idx]]  # x_t-1, x0_est
                            ccc = 0
                            # i = start_idx + i
                            # call the callback, if provided
                            # 进度条和回调函数：
                            #   在每个时间步结束时更新进度条。
                            #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                        if i == len(timesteps) - 1 or (
                                (i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                            progress_bar.update()
                            if callback is not None and i % callback_steps == 0:
                                callback(i, t, latents)

                        warp_start_idx +=len(unwarp_data)
                        ccc=0

                # 处理需要对齐的数据
                warp_start_idx = 0
                for num_batch, warp_data in enumerate(warped_images):
                    for num_image, data in enumerate(warp_data):  # 遍历图像帧
                        gloabl_num_image = warp_idxs[warp_start_idx]
                        image = data.unsqueeze(0)  # 图像数据

                        # compute Temporal Texture Guidance
                        # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                        if num_image != 0:  # if it's not the first image
                            x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                                0]  # convert x0_est to RGB
                            warped_prev_est = of.flow_warp(x0_est, flows[gloabl_num_image - 1],
                                                           interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                        # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                        # expand the latents if we are doing classifier free guidance
                        latent_model_input = torch.cat([latents[gloabl_num_image]] * 2) if do_classifier_free_guidance else \
                        latents[gloabl_num_image]
                        latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                        # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                        latent_model_input = torch.cat([latent_model_input, image], dim=1)

                        # controlnet(s) inference
                        # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                        if guess_mode and do_classifier_free_guidance:
                            # Infer ControlNet only for the conditional batch.
                            control_model_input = latents
                            control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                            controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                        else:
                            control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                            controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                        # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                        if isinstance(controlnet_keep[i], list):
                            cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                        else:
                            controlnet_cond_scale = controlnet_conditioning_scale
                            if isinstance(controlnet_cond_scale, list):
                                controlnet_cond_scale = controlnet_cond_scale[0]
                            cond_scale = controlnet_cond_scale * controlnet_keep[i]

                        # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                        if num_image == 0:
                            # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                            down_block_res_samples = None
                            mid_block_res_sample = None
                        else:
                            # predict with Temporal Conditioning Module
                            down_block_res_samples, mid_block_res_sample = self.controlnet(
                                control_model_input,
                                t,
                                encoder_hidden_states=controlnet_prompt_embeds,
                                controlnet_cond=warped_prev_est,
                                conditioning_scale=cond_scale,
                                # class_labels = noise_level,
                                guess_mode=guess_mode,
                                return_dict=False,
                                timestep_cond=None
                            )

                            if guess_mode and do_classifier_free_guidance:
                                # Infered ControlNet only for the conditional batch.
                                # To apply the output of ControlNet to both the unconditional and conditional batches,
                                # add 0 to the unconditional batch to keep it unchanged.
                                down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                          down_block_res_samples]
                                mid_block_res_sample = torch.cat(
                                    [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                        # predict the noise residual
                        # 使用 UNet 预测噪声残差（noise_pred）。
                        # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                        noise_pred = self.unet(
                            latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                            t,  # 当前的时间步 t
                            encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                            # class_labels = noise_level,
                            cross_attention_kwargs=cross_attention_kwargs,  # None
                            down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                            mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                            return_dict=False,
                        )[0]

                        # perform guidance
                        if do_classifier_free_guidance:
                            noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                            noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                        # compute the previous noisy sample x_t -> x_t-1
                        # 更新潜变量：
                        #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                        #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                        output = self.scheduler.step(noise_pred, t, latents[gloabl_num_image], **extra_step_kwargs)
                        latents[gloabl_num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                        warp_start_idx += 1
                        ccc = 0
                        # call the callback, if provided
                        # 进度条和回调函数：
                        #   在每个时间步结束时更新进度条。
                        #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                        # i = gloabl_num_image
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)
    #将输入的图像stack成一个大图
    def stack_images(self,images,batch_size=5):
        f = len(images)
        if f > batch_size:
            images_cat = [torch.cat(images[i:i + batch_size], dim=0) for i in range(0, f, batch_size)]
            return images_cat
        else:
            return [torch.cat(images, dim=0)]

    def process_images(self,images,ratio=0.1, batch_size=10):
        # 将 图像 cat 成之前的样子
        len_images = len(images)  # 总共有多少张图像
        # batch_size = 10
        # stack_images =self.stack_images(images,batch_size=batch_size)
        # len_stack = len(stack_images)
        step = math.floor(ratio * len_images)  # P 越大 效果越差
        # 总共产生多少个 时间约束步
        # generate_frame_indices(klist

        choices_indexs = sorted(np.random.choice(len_images, step, replace=False))
        all_idxs = []
        # generate_frame_indices(i, len_images, batch_size)
        for i in choices_indexs:
            all_idxs += generate_frame_indices(i, len_images, 5)
        all_idxs = sorted(list(set(all_idxs)))
        warped_images = []
        unwarped_images = []

        unwarp_idxs=[]
        for i in range(len_images):
            if i not in all_idxs:
                unwarp_idxs.append(i)

        # 处理 warp 序列
        tmp_images = []
        for idx, choice_id in enumerate(all_idxs):
            if idx > 0:
                # 判断id 与上一个连续
                if choice_id == all_idxs[idx - 1] + 1:
                    tmp_images.append(images[choice_id])
                else:
                    warped_images.append(torch.cat(tmp_images))
                    tmp_images = []
                    tmp_images.append(images[choice_id])
            else:
                # 添加 id
                tmp_images.append(images[choice_id])
        if len(tmp_images)>0:
            warped_images.append(torch.cat(tmp_images))
            tmp_images = []

        for i in range(len_images):
            if i not in all_idxs:
                unwarped_images.append(images[i])
        warped_images_tensor = warped_images
        # warped_images_tensor = torch.cat(warped_images, dim=0)
        if len(unwarped_images)>0:
            unwarped_images_tensor = self.stack_images(unwarped_images,batch_size=batch_size)
        else:
            unwarped_images_tensor = None
        # unwarped_images_tensor = torch.cat(unwarped_images, dim=0)
        return warped_images_tensor, unwarped_images_tensor,all_idxs,unwarp_idxs
        ccc = 0


# 双向传播的 stablevsr 模型
class StableBPVSRPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlBPNetModel, List[ControlBPNetModel], Tuple[ControlBPNetModel], MultiControlBPNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlBPNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlBPNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlBPNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlBPNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlBPNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlBPNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlBPNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlBPNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlBPNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlBPNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlBPNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlBPNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlBPNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlBPNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlBPNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlBPNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        # forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        # interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                # flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    # if num_image != 0:  # if it's not the first image
                    #     x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                    #         0]  # convert x0_est to RGB
                    #     warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                    #                                    interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    # if num_image == 0:
                    #     # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                    #     down_block_res_samples = None
                    #     mid_block_res_sample = None
                    # else:
                    #     # predict with Temporal Conditioning Module
                    #     down_block_res_samples, mid_block_res_sample = self.controlnet(
                    #         control_model_input,
                    #         t,
                    #         encoder_hidden_states=controlnet_prompt_embeds,
                    #         controlnet_cond=warped_prev_est,
                    #         conditioning_scale=cond_scale,
                    #         # class_labels = noise_level,
                    #         guess_mode=guess_mode,
                    #         return_dict=False,
                    #         timestep_cond=None
                    #     )
                    #
                    #     if guess_mode and do_classifier_free_guidance:
                    #         # Infered ControlNet only for the conditional batch.
                    #         # To apply the output of ControlNet to both the unconditional and conditional batches,
                    #         # add 0 to the unconditional batch to keep it unchanged.
                    #         down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                    #                                   down_block_res_samples]
                    #         mid_block_res_sample = torch.cat(
                    #             [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])
                    #




                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。

                    idxs = generate_frame_indices(num_image, len(images), self.controlnet.num_frames)                #取 5 张连续的图像帧
                    neighbours = torch.stack(upscaled_images,dim=1)
                    neighbours = neighbours[:,idxs]

                    controlnet_image = self.controlnet.control_image(of_model, neighbours)
                    down_block_res_samples, mid_block_res_sample = self.controlnet(
                        control_model_input,
                        t,
                        encoder_hidden_states=controlnet_prompt_embeds,
                        controlnet_cond=controlnet_image,
                        conditioning_scale=cond_scale,
                        # class_labels = noise_level,
                        guess_mode=guess_mode,
                        return_dict=False,
                        timestep_cond=None
                    )

                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


from evaluate_stage.bert_pytorch.model.bert import BERT_FILL2dAttentionPixelUpPos
from einops import rearrange
from basicsr.utils.color_util import rgb2ycbcr_pt,ycbcr2rgb
class StableVSRSuperXPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            superxModel: BERT_FILL2dAttentionPixelUpPos,
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            superxModel=superxModel,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image_ori = data  # 图像数据 2.0 * images - 1.0 --->  (images / 2 + 0.5).clamp(0, 1)
                    idxs = generate_frame_indices(num_image, len(images), 7)                #取 5 张连续的图像帧
                    neighbours = torch.stack(images,dim=1)
                    lq = neighbours[:,idxs]
                    #
                    # # # self.superxModel
                    b, f , _, _, _ = lq.shape                        # 加上这一行会导致结果崩坏
                    # # # # # 上采样 lq 输入
                    upscaled_lq = lq.clone().contiguous()                 # 加上这一步结果会出现剧烈退化
                    upscaled_lq = rearrange(lq, 'b f c h w -> (b f) c h w')
                    upscaled_lq = upscaled_lq.clone().contiguous()
                    # # lq_clone = upscaled_lq.clone()
                    #
                    upscaled_lq_ycbcr = rgb2ycbcr_pt(upscaled_lq)
                    # #
                    upscaled_lq_ycbcr = rearrange(upscaled_lq_ycbcr, '(b f) c h w -> b f c h w', b=b, f=f)
                    upscaled_lq_ycbcr = upscaled_lq_ycbcr.contiguous()
                    # #
                    upscaled_lq = upscaled_lq_ycbcr[:, :, [0], ...]
                    # #
                    # # #
                    # # # upscaled_lq = upscaled_lq * 2 - 1
                    idx = 7//2
                    # #
                    # # targets = upscaled_lq[:, [idx], ...]
                    inputs = upscaled_lq.clone()
                    # # # inputs[:,idx]=torch.zeros_like(targets)
                    # # inputs[:, [idx]] = torch.randn_like(targets)
                    inputs = inputs.to(self.device)
                    #
                    outputs = self.superxModel(inputs, idx)
                    outputs_show = outputs
                    # # outputs_show = (outputs / 2 + 0.5).clamp(0, 1)
                    #
                    outputs_show = torch.cat(
                        [outputs_show.to(upscaled_lq_ycbcr.device), upscaled_lq_ycbcr[:, :, 1:, ...]], dim=2)

                    #
                    # # 转换成rgb的tensor
                    outputs_show = rearrange(outputs_show, 'b f c h w -> (b f) h w c')
                    outputs_show = outputs_show.contiguous()
                    outputs_show = torch.from_numpy(ycbcr2rgb(outputs_show.cpu().contiguous().numpy()))
                    outputs_show = outputs_show.to(self.device)
                    outputs_show = rearrange(outputs_show, '(b f) h w c -> b f c h w', b=b, f=f)

                    image = outputs_show[:,7//2]
                    # image = image_ori
                    # image = data

                    # image_ori = (image_ori / 2 + 0.5).clamp(0, 1)
                    # image_ori_np = (image_ori[0].permute(1,2,0).cpu().contiguous().numpy()*255.0).astype(np.uint8)
                    # image_np = (image[0].permute(1,2,0).cpu().contiguous().numpy()*255.0).astype(np.uint8)
                    # image_show = np.concatenate([image_ori_np, image_np], axis=1)
                    #
                    # cv2.imwrite(f'/data/LWKEXP/stablevsr/evaluate_stage/logimage/{num_image}.png', image_show[:,:,::-1])
                    #

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


from torch import nn
class StableMIAVSRPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            miavsr: MIAVSR,
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
            mid_channels: int = 1024,
            slide_frames: int = 5,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            miavsr=miavsr,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)
        # self.position_embeddings = nn.Embedding(slide_frames, mid_channels)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        # forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        # interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                # flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)


                    idxs = generate_frame_indices(num_image, len(images), 5)                #取 5 张连续的图像帧
                    neighbours = torch.stack(images,dim=1)
                    neighbours = neighbours[:,idxs]

                    neighbours,_ = self.miavsr(neighbours)                                            # b f c 4h 4w
                    # 获得 controlnet 处理的时间嵌入
                    down_block_res_samples, mid_block_res_sample = self.time_embeddings(neighbours,i,t,latents,latent_model_input,prompt_embeds,guess_mode,do_classifier_free_guidance,controlnet_keep,controlnet_conditioning_scale)

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


    def time_embeddings(self,neighbours,i,t,latents,latent_model_input,prompt_embeds,guess_mode,do_classifier_free_guidance,controlnet_keep,controlnet_conditioning_scale):
        # compute Temporal Texture Guidanc
        # 根据 neighbours 计算对齐特征
        b,f,c,h,w = neighbours.shape
        mid_idx = f//2                          #中间帧的序号

        # if num_image != 0:  # if it's not the first image
        #     x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
        #         0]  # convert x0_est to RGB
        #     warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
        #                                    interp_mode=interp_mode)  # warp it to current frame            #光流对齐
        down_block_res_samples_list=[]
        mid_block_res_sample_list=[]
        for idx in range(0,f):
            if idx == mid_idx:
                continue
            # pos = idx - mid_idx

            #计算位置嵌入特征
            # pos_embed = self.position_embeddings(torch.tensor(idx))
            # mid_block_res_sample 1 1204 23 40
            #mid_block_res_sample

            # controlnet(s) inference
            # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            if guess_mode and do_classifier_free_guidance:
                # Infer ControlNet only for the conditional batch.
                control_model_input = latents
                control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
            else:
                control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

            # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            if isinstance(controlnet_keep[i], list):
                cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
            else:
                controlnet_cond_scale = controlnet_conditioning_scale
                if isinstance(controlnet_cond_scale, list):
                    controlnet_cond_scale = controlnet_cond_scale[0]
                cond_scale = controlnet_cond_scale * controlnet_keep[i]

            # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
            warped_prev_est = neighbours[:,mid_idx]                             #前一时刻的特征残差
            # predict with Temporal Conditioning Module
            down_block_res_samples, mid_block_res_sample = self.controlnet(
                control_model_input,
                t,
                encoder_hidden_states=controlnet_prompt_embeds,
                controlnet_cond=warped_prev_est,
                conditioning_scale=cond_scale,
                # class_labels = noise_level,
                guess_mode=guess_mode,
                return_dict=False,
                timestep_cond=None
            )

            if guess_mode and do_classifier_free_guidance:
                # Infered ControlNet only for the conditional batch.
                # To apply the output of ControlNet to both the unconditional and conditional batches,
                # add 0 to the unconditional batch to keep it unchanged.
                down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                          down_block_res_samples]
                mid_block_res_sample = torch.cat(
                    [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])


            # mid_block_res_sample += pos_embed
            down_block_res_samples_list.append(down_block_res_samples)
            mid_block_res_sample_list.append(mid_block_res_sample)

        down_block_res_samples=[]
        frames = len(down_block_res_samples_list)
        if frames>0:
            layers=len(down_block_res_samples_list[0])
            for i_layer in range(layers):
                down_features = [down_block_res_samples_list[f][i_layer] for f in range(frames)]
                down_block_res_samples.append(torch.sum(torch.stack(down_features),dim=0))

        # down_block_res_samples = torch.mean(torch.stack(down_block_res_samples_list),dim=0)
        # mid_block_res_sample = torch.mean(torch.stack(mid_block_res_sample_list),dim=0)
        mid_block_res_sample = torch.sum(torch.stack(mid_block_res_sample_list),dim=0)
        return down_block_res_samples, mid_block_res_sample

    def gettime_embeddings(self,neighbours,t,latent_model_input,prompt_embeds,guess_mode=False):
        # compute Temporal Texture Guidanc
        # 根据 neighbours 计算对齐特征
        b,f,c,h,w = neighbours.shape
        mid_idx = f//2                          #中间帧的序号

        # if num_image != 0:  # if it's not the first image
        #     x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
        #         0]  # convert x0_est to RGB
        #     warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
        #                                    interp_mode=interp_mode)  # warp it to current frame            #光流对齐
        down_block_res_samples_list=[]
        mid_block_res_sample_list=[]
        for idx in range(0,f):
            if idx == mid_idx:
                continue
            # pos = idx - mid_idx

            #计算位置嵌入特征
            # pos_embed = self.position_embeddings(torch.tensor(idx))
            # mid_block_res_sample 1 1204 23 40
            #mid_block_res_sample

            # controlnet(s) inference
            # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
            controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

            # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            cond_scale = 1.0

            # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
            warped_prev_est = neighbours[:,mid_idx]                             #前一时刻的特征残差
            # predict with Temporal Conditioning Module
            down_block_res_samples, mid_block_res_sample = self.controlnet(
                control_model_input,
                t,
                encoder_hidden_states=controlnet_prompt_embeds,
                controlnet_cond=warped_prev_est,
                conditioning_scale=cond_scale,
                # class_labels = noise_level,
                guess_mode=guess_mode,
                return_dict=False,
                timestep_cond=None
            )

            # mid_block_res_sample += pos_embed
            down_block_res_samples_list.append(down_block_res_samples)
            mid_block_res_sample_list.append(mid_block_res_sample)

        down_block_res_samples=[]
        frames = len(down_block_res_samples_list)
        if frames>0:
            layers=len(down_block_res_samples_list[0])
            for i_layer in range(layers):
                down_features = [down_block_res_samples_list[f][i_layer] for f in range(frames)]
                down_block_res_samples.append(torch.sum(torch.stack(down_features),dim=0))

        # down_block_res_samples = torch.mean(torch.stack(down_block_res_samples_list),dim=0)
        # mid_block_res_sample = torch.mean(torch.stack(mid_block_res_sample_list),dim=0)
        mid_block_res_sample = torch.sum(torch.stack(mid_block_res_sample_list),dim=0)
        return down_block_res_samples, mid_block_res_sample

# 用传播模块 获取 control_image
class StableVSRMIA2Pipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            miavsr: MIAVSR,
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            miavsr=miavsr,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            # 100 [1 3 180 320]
            images_tensor=torch.stack(images,dim=1)
            upscaled_images,_ = self.miavsr(images_tensor) # b f c h w --> b f c 4h 4w
            upscaled_images = rearrange(upscaled_images, 'b f c h w -> f b c h w')
            # upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280
            upscaled_images = list(upscaled_images)
            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320 从 image 到 latent

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)

# 用传播模块 获取 在利用Unet 进行超分辨率重建之前先 充分提取融合多帧之间的空间信息
class StableVSRMIA3Pipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型
        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlSpatialNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlSpatialNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlSpatialNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlSpatialNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlSpatialNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlSpatialNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlSpatialNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlSpatialNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlSpatialNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            # 100 [1 3 180 320]
            # images_tensor = torch.stack(images,dim=1)
            # upscaled_images,_ = self.miavsr(images_tensor) # b f c h w --> b f c 4h 4w
            # upscaled_images = rearrange(upscaled_images, 'b f c h w -> f b c h w')
            # upscaled_images = list(upscaled_images)

            #利用双三次立方进行4倍上采样操作
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280

            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlSpatialNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320  初始化 100 个随机噪声

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlSpatialNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            len_images = len(images)     #一共有多少张影像
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # 获取相邻数据 索引
                    neighbour_idxs = generate_frame_indices(num_image, len_images,  self.controlnet.batch_len)
                    images_tmp = [images[idx] for idx in neighbour_idxs]
                    images_tensor = torch.stack(images_tmp,dim=1).to(device)        # 1 7 3 64 64
                    # 这里有 7 张相邻帧 如何对这7张相邻帧进行充分的空间建模 融合多帧的空间信息 帮助重新高频细节信息
                    # image 1 3 64 64 当前操作时噪声 1 4 64 64 拼上 image 1 3 64 64 --》 1 7 64 64
                    # 这里想办法对 image 进行处理操作
                    image_tmp = self.controlnet.control_image(of_model=of_model,images=images_tensor)


                    ccc=0



                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image_tmp], dim=1)
                    # latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)

from modules.MaskSR3.model.sr3_modules.diffusion import GaussianDiffusion
# StableMaskSR3 流水线
class StableVSRMASKPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            mask_net: GaussianDiffusion,
            controlnet: Union[ControlNetModel, List[ControlNetModel], Tuple[ControlNetModel], MultiControlNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型

        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            mask_net= mask_net,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlSpatialNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlSpatialNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlSpatialNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlSpatialNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlSpatialNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlSpatialNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlSpatialNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlSpatialNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlSpatialNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlSpatialNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            # 100 [1 3 180 320]
            # images_tensor = torch.stack(images,dim=1)
            # upscaled_images,_ = self.miavsr(images_tensor) # b f c h w --> b f c 4h 4w
            # upscaled_images = rearrange(upscaled_images, 'b f c h w -> f b c h w')
            # upscaled_images = list(upscaled_images)

            #利用双三次立方进行4倍上采样操作
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280

            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlSpatialNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320  初始化 100 个随机噪声

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlSpatialNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            # for t, for image --> frame wise sampling
            len_images = len(images)     #一共有多少张影像
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    # 获取相邻数据 索引
                    neighbour_idxs = generate_frame_indices(num_image, len_images,  self.controlnet.batch_len)
                    images_tmp = [images[idx] for idx in neighbour_idxs]
                    images_tensor = torch.stack(images_tmp,dim=1).to(device)        # 1 7 3 64 64
                    # 这里有 7 张相邻帧 如何对这7张相邻帧进行充分的空间建模 融合多帧的空间信息 帮助重新高频细节信息
                    # image 1 3 64 64 当前操作时噪声 1 4 64 64 拼上 image 1 3 64 64 --》 1 7 64 64
                    # 这里想办法对 image 进行处理操作
                    image_tmp = self.controlnet.control_image(of_model=of_model,images=images_tensor)


                    ccc=0



                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]
                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image_tmp], dim=1)
                    # latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)

                    # compute the previous noisy sample x_t -> x_t-1
                    # 更新潜变量：
                    #  使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
                    #  获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
                    output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                    latents[num_image], x0_est = output.prev_sample, output.pred_original_sample  # x_t-1, x0_est

                    # call the callback, if provided
                    # 进度条和回调函数：
                    #   在每个时间步结束时更新进度条。
                    #   如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
                    if i == len(timesteps) - 1 or ((i + 1) > num_warmup_steps and (i + 1) % self.scheduler.order == 0):
                        progress_bar.update()
                        if callback is not None and i % callback_steps == 0:
                            callback(i, t, latents)

                # reverse all for bidirectional sampling
                images.reverse()
                latents.reverse()
                upscaled_images.reverse()
                reversed = not reversed
        # 双向采样：
        #  在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
        #  切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        # restore the right frame order
        if reversed:
            latents.reverse()

        # If we do sequential model offloading, let's offload unet and controlnet
        # manually for max memory savings
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.unet.to("cpu")
            self.controlnet.to("cpu")
            torch.cuda.empty_cache()

        if not output_type == "latent":
            images = [self.vae.decode(latent / self.vae.config.scaling_factor, return_dict=False)[0] for latent in
                      latents]
        else:
            image = latents
            has_nsfw_concept = None

        has_nsfw_concept = None
        if has_nsfw_concept is None:
            do_denormalize = [True] * image[0].shape[0]
        else:
            do_denormalize = [not has_nsfw for has_nsfw in has_nsfw_concept]

        images = [self.image_processor.postprocess(image, output_type=output_type, do_denormalize=do_denormalize) for
                  image in images]

        # Offload last model to CPU
        if hasattr(self, "final_offload_hook") and self.final_offload_hook is not None:
            self.final_offload_hook.offload()

        if not return_dict:
            return (image, has_nsfw_concept)

        return StableDiffusionPipelineOutput(images=images, nsfw_content_detected=has_nsfw_concept)


# StableRevampVSR 流水线
class StableVSRRevampPipeline(
    DiffusionPipeline, TextualInversionLoaderMixin, LoraLoaderMixin, FromSingleFileMixin
):
    r"""
    Pipeline for text-to-image generation using Stable Diffusion with ControlNet guidance.

    This model inherits from [`DiffusionPipeline`]. Check the superclass documentation for the generic methods
    implemented for all pipelines (downloading, saving, running on a particular device, etc.).

    The pipeline also inherits the following loading methods:
        - [`~loaders.TextualInversionLoaderMixin.load_textual_inversion`] for loading textual inversion embeddings

    Args:
        vae ([`AutoencoderKL`]):
            Variational Auto-Encoder (VAE) model to encode and decode images to and from latent representations.
        text_encoder ([`~transformers.CLIPTextModel`]):
            Frozen text-encoder ([clip-vit-large-patch14](https://huggingface.co/openai/clip-vit-large-patch14)).
        tokenizer ([`~transformers.CLIPTokenizer`]):
            A `CLIPTokenizer` to tokenize text.
        unet ([`UNet2DConditionModel`]):
            A `UNet2DConditionModel` to denoise the encoded image latents.
        controlnet ([`ControlNetModel`] or `List[ControlNetModel]`):
            Provides additional conditioning to the `unet` during the denoising process. If you set multiple
            ControlNets as a list, the outputs from each ControlNet are added together to create one combined
            additional conditioning.
        scheduler ([`SchedulerMixin`]):
            A scheduler to be used in combination with `unet` to denoise the encoded image latents. Can be one of
            [`DDIMScheduler`], [`LMSDiscreteScheduler`], or [`PNDMScheduler`].
        safety_checker ([`StableDiffusionSafetyChecker`]):
            Classification module that estimates whether generated images could be considered offensive or harmful.
            Please refer to the [model card](https://huggingface.co/runwayml/stable-diffusion-v1-5) for more details
            about a model's potential harms.
        feature_extractor ([`~transformers.CLIPImageProcessor`]):
            A `CLIPImageProcessor` to extract features from generated images; used as inputs to the `safety_checker`.
    """
    _optional_components = ["safety_checker", "feature_extractor"]

    def __init__(
            self,
            vae: AutoencoderKL,
            text_encoder: CLIPTextModel,
            tokenizer: CLIPTokenizer,
            unet: UNet2DConditionModel,
            # mask_net: GaussianDiffusion,
            controlnet: Union[ControlRevampNetModel, List[ControlRevampNetModel], Tuple[ControlRevampNetModel], MultiControlRevampNetModel],
            scheduler: KarrasDiffusionSchedulers,
            safety_checker: StableDiffusionSafetyChecker,
            feature_extractor: CLIPImageProcessor,
            requires_safety_checker: bool = True,
    ):
        super().__init__()

        if safety_checker is None and requires_safety_checker:
            logger.warning(
                f"You have disabled the safety checker for {self.__class__} by passing `safety_checker=None`. Ensure"
                " that you abide to the conditions of the Stable Diffusion license and do not expose unfiltered"
                " results in services or applications open to the public. Both the diffusers team and Hugging Face"
                " strongly recommend to keep the safety filter enabled in all public facing circumstances, disabling"
                " it only for use-cases that involve analyzing network behavior or auditing its results. For more"
                " information, please have a look at https://github.com/huggingface/diffusers/pull/254 ."
            )

        if safety_checker is not None and feature_extractor is None:
            raise ValueError(
                "Make sure to define a feature extractor when loading {self.__class__} if you want to use the safety"
                " checker. If you do not want to use the safety checker, you can pass `'safety_checker=None'` instead."
            )
        # 如果传入的是多个控制条件 使用 MultiControlNetModel 类
        if isinstance(controlnet, (list, tuple)):
            controlnet = MultiControlNetModel(controlnet)
        # 注册模型

        self.register_modules(
            vae=vae,
            text_encoder=text_encoder,
            tokenizer=tokenizer,
            unet=unet,
            # mask_net= mask_net,
            controlnet=controlnet,
            scheduler=scheduler,
            safety_checker=safety_checker,
            feature_extractor=feature_extractor,
        )

        self.vae_scale_factor = 2 ** (len(self.vae.config.block_out_channels) - 1)
        self.image_processor = VaeImageProcessor(vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True)
        self.control_image_processor = VaeImageProcessor(
            vae_scale_factor=self.vae_scale_factor, do_convert_rgb=True, do_normalize=True
        )
        self.register_to_config(requires_safety_checker=requires_safety_checker)

    # 将解码过程拆分成多个步骤执行，可以节省内存
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_slicing
    def enable_vae_slicing(self):
        r"""
        Enable sliced VAE decoding. When this option is enabled, the VAE will split the input tensor in slices to
        compute decoding in several steps. This is useful to save some memory and allow larger batch sizes.
        """
        self.vae.enable_slicing()

    # 将解码过程重新设置成一步执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_slicing
    def disable_vae_slicing(self):
        r"""
        Disable sliced VAE decoding. If `enable_vae_slicing` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_slicing()

    # 节省内存用 可以将输出分解成多个块进行处理
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.enable_vae_tiling
    def enable_vae_tiling(self):
        r"""
        Enable tiled VAE decoding. When this option is enabled, the VAE will split the input tensor into tiles to
        compute decoding and encoding in several steps. This is useful for saving a large amount of memory and to allow
        processing larger images.
        """
        self.vae.enable_tiling()

    # 不拆块 完整的输入执行
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.disable_vae_tiling
    def disable_vae_tiling(self):
        r"""
        Disable tiled VAE decoding. If `enable_vae_tiling` was previously enabled, this method will go back to
        computing decoding in one step.
        """
        self.vae.disable_tiling()

    # 将模型卸载到CPU中，在执行forward的时候转移到GPU上
    def enable_model_cpu_offload(self, gpu_id=0):
        r"""
        Offloads all models to CPU using accelerate, reducing memory usage with a low impact on performance. Compared
        to `enable_sequential_cpu_offload`, this method moves one whole model at a time to the GPU when its `forward`
        method is called, and the model remains in GPU until the next model runs. Memory savings are lower than with
        `enable_sequential_cpu_offload`, but performance is much better due to the iterative execution of the `unet`.
        """
        if is_accelerate_available() and is_accelerate_version(">=", "0.17.0.dev0"):
            from accelerate import cpu_offload_with_hook
        else:
            raise ImportError("`enable_model_cpu_offload` requires `accelerate v0.17.0` or higher.")

        device = torch.device(f"cuda:{gpu_id}")

        hook = None
        for cpu_offloaded_model in [self.text_encoder, self.unet, self.vae]:
            _, hook = cpu_offload_with_hook(cpu_offloaded_model, device, prev_module_hook=hook)

        if self.safety_checker is not None:
            # the safety checker can offload the vae again
            _, hook = cpu_offload_with_hook(self.safety_checker, device, prev_module_hook=hook)

        # control net hook has be manually offloaded as it alternates with unet
        cpu_offload_with_hook(self.controlnet, device)

        # We'll offload the last model manually.
        self.final_offload_hook = hook

    # 对提示进行编码
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline._encode_prompt
    def _encode_prompt(
            self,
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        deprecation_message = "`_encode_prompt()` is deprecated and it will be removed in a future version. Use `encode_prompt()` instead. Also, be aware that the output format changed from a concatenated tensor to a tuple."
        deprecate("_encode_prompt()", "1.0.0", deprecation_message, standard_warn=False)

        prompt_embeds_tuple = self.encode_prompt(
            prompt=prompt,
            device=device,
            num_images_per_prompt=num_images_per_prompt,
            do_classifier_free_guidance=do_classifier_free_guidance,
            negative_prompt=negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=lora_scale,
        )

        # concatenate for backwards comp
        prompt_embeds = torch.cat([prompt_embeds_tuple[1], prompt_embeds_tuple[0]])

        return prompt_embeds

    # 把提示信息编码成隐特征
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.encode_prompt
    '''
    这段代码是一个函数 encode_prompt 的实现，它将输入的文本提示（prompt）编码为文本编码器的隐藏状态（prompt_embeds），并为分类器自由引导（classifier-free guidance）生成无条件嵌入（negative_prompt_embeds）。以下是代码的详细中文解释：
函数参数

    prompt：输入的文本提示，可以是一个字符串（str），也可以是一个字符串列表（List[str]）。它表示要生成图像的描述。
    device：运行设备，通常是 torch.device，例如 "cuda" 或 "cpu"。
    num_images_per_prompt：每个提示需要生成的图像数量。
    do_classifier_free_guidance：布尔值，表示是否使用分类器自由引导。如果为 True，则需要生成无条件嵌入。
    negative_prompt：负向提示，用于指导生成图像时避免的内容。可以是字符串或字符串列表。如果未定义，则必须提供 negative_prompt_embeds。
    prompt_embeds：预生成的文本嵌入（torch.FloatTensor）。如果提供，则直接使用这些嵌入，而不从 prompt 中生成。
    negative_prompt_embeds：预生成的负向文本嵌入。如果提供，则直接使用这些嵌入，而不从 negative_prompt 中生成。
    lora_scale：一个可选的浮点数，表示应用于文本编码器中所有 LoRA 层的缩放因子。如果加载了 LoRA 层，则会使用此参数。

函数功能

    处理 LoRA 缩放：如果提供了 lora_scale，并且模型是 LoraLoaderMixin 的实例，则将 lora_scale 设置到模型中，以便在文本编码器中正确应用 LoRA。
    确定批大小：
        如果 prompt 是字符串，则批大小为 1。
        如果 prompt 是列表，则批大小为列表的长度。
        如果 prompt 为空，但提供了 prompt_embeds，则批大小为 prompt_embeds 的第一个维度。
    生成文本嵌入（prompt_embeds）：
        如果未提供 prompt_embeds，则需要从 prompt 中生成文本嵌入。
        使用 tokenizer 对 prompt 进行分词和编码，生成 text_input_ids。
        检查是否截断了输入文本，如果截断，则记录警告信息。
        如果文本编码器支持注意力掩码（attention_mask），则使用掩码；否则不使用。
        使用文本编码器（text_encoder）对输入进行编码，生成 prompt_embeds。
    调整嵌入的类型和设备：
        根据文本编码器或 U-Net 的数据类型（dtype），将 prompt_embeds 转换为相同的类型和设备。
    扩展嵌入以匹配生成数量：
        将 prompt_embeds 重复 num_images_per_prompt 次，以匹配每个提示生成的图像数量。
    生成无条件嵌入（negative_prompt_embeds）：
        如果启用了分类器自由引导（do_classifier_free_guidance），并且未提供 negative_prompt_embeds，则需要生成无条件嵌入。
        根据 negative_prompt 的类型（字符串或列表），生成无条件嵌入。
        使用 tokenizer 对 negative_prompt 进行分词和编码，生成 uncond_input。
        使用文本编码器对无条件输入进行编码，生成 negative_prompt_embeds。
        将 negative_prompt_embeds 调整为与 prompt_embeds 相同的类型和设备，并重复 num_images_per_prompt 次。
    返回结果：
        返回 prompt_embeds 和 negative_prompt_embeds。

总结
这段代码的主要作用是将文本提示（prompt）和负向提示（negative_prompt）编码为文本嵌入（prompt_embeds 和 negative_prompt_embeds），并根据需要进行扩展和调整，以便用于图像生成模型（如 Stable Diffusion）。它还支持预生成的嵌入、LoRA 缩放以及分类器自由引导等功能。
    '''

    def encode_prompt(
            self,
            prompt,  # 提示  一到多个
            device,  # 运行设备
            num_images_per_prompt,  # 每个提示生成多少图片
            do_classifier_free_guidance,  # 是否使用分类置信度
            negative_prompt=None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            lora_scale: Optional[float] = None,
    ):
        r"""
        Encodes the prompt into text encoder hidden states.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                prompt to be encoded
            device: (`torch.device`):
                torch device
            num_images_per_prompt (`int`):
                number of images that should be generated per prompt
            do_classifier_free_guidance (`bool`):
                whether to use classifier free guidance or not
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts not to guide the image generation. If not defined, one has to pass
                `negative_prompt_embeds` instead. Ignored when not using guidance (i.e., ignored if `guidance_scale` is
                less than `1`).
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt weighting. If not
                provided, text embeddings will be generated from `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs, *e.g.* prompt
                weighting. If not provided, negative_prompt_embeds will be generated from `negative_prompt` input
                argument.
            lora_scale (`float`, *optional*):
                A lora scale that will be applied to all LoRA layers of the text encoder if LoRA layers are loaded.
        """
        # set lora scale so that monkey patched LoRA
        # function of text encoder can correctly access it
        if lora_scale is not None and isinstance(self, LoraLoaderMixin):
            self._lora_scale = lora_scale

        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]

        if prompt_embeds is None:
            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                prompt = self.maybe_convert_prompt(prompt, self.tokenizer)

            text_inputs = self.tokenizer(
                prompt,
                padding="max_length",
                max_length=self.tokenizer.model_max_length,
                truncation=True,
                return_tensors="pt",
            )
            text_input_ids = text_inputs.input_ids
            untruncated_ids = self.tokenizer(prompt, padding="longest", return_tensors="pt").input_ids

            if untruncated_ids.shape[-1] >= text_input_ids.shape[-1] and not torch.equal(
                    text_input_ids, untruncated_ids
            ):
                removed_text = self.tokenizer.batch_decode(
                    untruncated_ids[:, self.tokenizer.model_max_length - 1: -1]
                )
                logger.warning(
                    "The following part of your input was truncated because CLIP can only handle sequences up to"
                    f" {self.tokenizer.model_max_length} tokens: {removed_text}"
                )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = text_inputs.attention_mask.to(device)
            else:
                attention_mask = None

            prompt_embeds = self.text_encoder(
                text_input_ids.to(device),
                attention_mask=attention_mask,
            )
            prompt_embeds = prompt_embeds[0]

        if self.text_encoder is not None:
            prompt_embeds_dtype = self.text_encoder.dtype
        elif self.unet is not None:
            prompt_embeds_dtype = self.unet.dtype
        else:
            prompt_embeds_dtype = prompt_embeds.dtype

        prompt_embeds = prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

        bs_embed, seq_len, _ = prompt_embeds.shape
        # duplicate text embeddings for each generation per prompt, using mps friendly method
        prompt_embeds = prompt_embeds.repeat(1, num_images_per_prompt, 1)
        prompt_embeds = prompt_embeds.view(bs_embed * num_images_per_prompt, seq_len, -1)

        # get unconditional embeddings for classifier free guidance
        if do_classifier_free_guidance and negative_prompt_embeds is None:
            uncond_tokens: List[str]
            if negative_prompt is None:
                uncond_tokens = [""] * batch_size
            elif prompt is not None and type(prompt) is not type(negative_prompt):
                raise TypeError(
                    f"`negative_prompt` should be the same type to `prompt`, but got {type(negative_prompt)} !="
                    f" {type(prompt)}."
                )
            elif isinstance(negative_prompt, str):
                uncond_tokens = [negative_prompt]
            elif batch_size != len(negative_prompt):
                raise ValueError(
                    f"`negative_prompt`: {negative_prompt} has batch size {len(negative_prompt)}, but `prompt`:"
                    f" {prompt} has batch size {batch_size}. Please make sure that passed `negative_prompt` matches"
                    " the batch size of `prompt`."
                )
            else:
                uncond_tokens = negative_prompt

            # textual inversion: procecss multi-vector tokens if necessary
            if isinstance(self, TextualInversionLoaderMixin):
                uncond_tokens = self.maybe_convert_prompt(uncond_tokens, self.tokenizer)

            max_length = prompt_embeds.shape[1]
            uncond_input = self.tokenizer(
                uncond_tokens,
                padding="max_length",
                max_length=max_length,
                truncation=True,
                return_tensors="pt",
            )

            if hasattr(self.text_encoder.config, "use_attention_mask") and self.text_encoder.config.use_attention_mask:
                attention_mask = uncond_input.attention_mask.to(device)
            else:
                attention_mask = None

            negative_prompt_embeds = self.text_encoder(
                uncond_input.input_ids.to(device),
                attention_mask=attention_mask,
            )
            negative_prompt_embeds = negative_prompt_embeds[0]

        if do_classifier_free_guidance:
            # duplicate unconditional embeddings for each generation per prompt, using mps friendly method
            seq_len = negative_prompt_embeds.shape[1]

            negative_prompt_embeds = negative_prompt_embeds.to(dtype=prompt_embeds_dtype, device=device)

            negative_prompt_embeds = negative_prompt_embeds.repeat(1, num_images_per_prompt, 1)
            negative_prompt_embeds = negative_prompt_embeds.view(batch_size * num_images_per_prompt, seq_len, -1)

        return prompt_embeds, negative_prompt_embeds

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.run_safety_checker
    def run_safety_checker(self, image, device, dtype):
        if self.safety_checker is None:
            has_nsfw_concept = None
        else:
            if torch.is_tensor(image):
                feature_extractor_input = self.image_processor.postprocess(image, output_type="pil")
            else:
                feature_extractor_input = self.image_processor.numpy_to_pil(image)
            safety_checker_input = self.feature_extractor(feature_extractor_input, return_tensors="pt").to(device)
            image, has_nsfw_concept = self.safety_checker(
                images=image, clip_input=safety_checker_input.pixel_values.to(dtype)
            )
        return image, has_nsfw_concept

    # 这个方法将被弃用 使用 VaeImageProcessor.postprocess(...) 替代
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.decode_latents
    def decode_latents(self, latents):
        deprecation_message = "The decode_latents method is deprecated and will be removed in 1.0.0. Please use VaeImageProcessor.postprocess(...) instead"
        deprecate("decode_latents", "1.0.0", deprecation_message, standard_warn=False)

        latents = 1 / self.vae.config.scaling_factor * latents
        image = self.vae.decode(latents, return_dict=False)[0]
        image = (image / 2 + 0.5).clamp(0, 1)
        # we always cast to float32 as this does not cause significant overhead and is compatible with bfloat16
        image = image.cpu().permute(0, 2, 3, 1).float().numpy()
        return image

    # 额外的采样设置 eta 只 针对 DDIM 采样器有用 其他的采样器会忽略该项设置
    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_extra_step_kwargs
    def prepare_extra_step_kwargs(self, generator, eta):
        # prepare extra kwargs for the scheduler step, since not all schedulers have the same signature
        # eta (η) is only used with the DDIMScheduler, it will be ignored for other schedulers.
        # eta corresponds to η in DDIM paper: https://arxiv.org/abs/2010.02502
        # and should be between [0, 1]

        accepts_eta = "eta" in set(inspect.signature(self.scheduler.step).parameters.keys())
        extra_step_kwargs = {}
        if accepts_eta:
            extra_step_kwargs["eta"] = eta

        # check if the scheduler accepts generator
        '''
        使用 inspect.signature 检查调度器的 step 方法是否接受 generator 参数。如果支持，则将 generator 添加到 extra_step_kwargs 中
        '''
        accepts_generator = "generator" in set(inspect.signature(self.scheduler.step).parameters.keys())
        if accepts_generator:
            extra_step_kwargs["generator"] = generator
        return extra_step_kwargs

    # 检查输入信息
    def check_inputs(
            self,
            prompt,
            image,
            callback_steps,  # callback 如果设置必须设置为正整数
            negative_prompt=None,
            prompt_embeds=None,
            negative_prompt_embeds=None,
            controlnet_conditioning_scale=1.0,
            control_guidance_start=0.0,
            control_guidance_end=1.0,
    ):
        if (callback_steps is None) or (
                callback_steps is not None and (not isinstance(callback_steps, int) or callback_steps <= 0)
        ):
            raise ValueError(
                f"`callback_steps` has to be a positive integer but is {callback_steps} of type"
                f" {type(callback_steps)}."
            )

        if prompt is not None and prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `prompt`: {prompt} and `prompt_embeds`: {prompt_embeds}. Please make sure to"
                " only forward one of the two."
            )
        elif prompt is None and prompt_embeds is None:
            raise ValueError(
                "Provide either `prompt` or `prompt_embeds`. Cannot leave both `prompt` and `prompt_embeds` undefined."
            )
        elif prompt is not None and (not isinstance(prompt, str) and not isinstance(prompt, list)):
            raise ValueError(f"`prompt` has to be of type `str` or `list` but is {type(prompt)}")

        if negative_prompt is not None and negative_prompt_embeds is not None:
            raise ValueError(
                f"Cannot forward both `negative_prompt`: {negative_prompt} and `negative_prompt_embeds`:"
                f" {negative_prompt_embeds}. Please make sure to only forward one of the two."
            )

        if prompt_embeds is not None and negative_prompt_embeds is not None:
            if prompt_embeds.shape != negative_prompt_embeds.shape:
                raise ValueError(
                    "`prompt_embeds` and `negative_prompt_embeds` must have the same shape when passed directly, but"
                    f" got: `prompt_embeds` {prompt_embeds.shape} != `negative_prompt_embeds`"
                    f" {negative_prompt_embeds.shape}."
                )

        # `prompt` needs more sophisticated handling when there are multiple
        # conditionings.
        if isinstance(self.controlnet, MultiControlRevampNetModel):
            if isinstance(prompt, list):
                logger.warning(
                    f"You have {len(self.controlnet.nets)} ControlNets and you have passed {len(prompt)}"
                    " prompts. The conditionings will be fixed across the prompts."
                )

        # Check `image`
        is_compiled = hasattr(F, "scaled_dot_product_attention") and isinstance(
            self.controlnet, torch._dynamo.eval_frame.OptimizedModule
        )
        if (
                isinstance(self.controlnet, ControlRevampNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlRevampNetModel)
        ):
            self.check_image(image, prompt, prompt_embeds)
        elif (
                isinstance(self.controlnet, MultiControlRevampNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlRevampNetModel)
        ):
            if not isinstance(image, list):
                raise TypeError("For multiple controlnets: `image` must be type `list`")

            # When `image` is a nested list:
            # (e.g. [[canny_image_1, pose_image_1], [canny_image_2, pose_image_2]])
            elif any(isinstance(i, list) for i in image):
                raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif len(image) != len(self.controlnet.nets):
                raise ValueError(
                    f"For multiple controlnets: `image` must have the same length as the number of controlnets, but got {len(image)} images and {len(self.controlnet.nets)} ControlNets."
                )

            for image_ in image:
                self.check_image(image_, prompt, prompt_embeds)
        else:
            assert False

        # Check `controlnet_conditioning_scale`
        if (
                isinstance(self.controlnet, ControlRevampNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, ControlRevampNetModel)
        ):
            if not isinstance(controlnet_conditioning_scale, float):
                raise TypeError("For single controlnet: `controlnet_conditioning_scale` must be type `float`.")
        elif (
                isinstance(self.controlnet, MultiControlRevampNetModel)
                or is_compiled
                and isinstance(self.controlnet._orig_mod, MultiControlRevampNetModel)
        ):
            if isinstance(controlnet_conditioning_scale, list):
                if any(isinstance(i, list) for i in controlnet_conditioning_scale):
                    raise ValueError("A single batch of multiple conditionings are supported at the moment.")
            elif isinstance(controlnet_conditioning_scale, list) and len(controlnet_conditioning_scale) != len(
                    self.controlnet.nets
            ):
                raise ValueError(
                    "For multiple controlnets: When `controlnet_conditioning_scale` is specified as `list`, it must have"
                    " the same length as the number of controlnets"
                )
        else:
            assert False

        if not isinstance(control_guidance_start, (tuple, list)):
            control_guidance_start = [control_guidance_start]

        if not isinstance(control_guidance_end, (tuple, list)):
            control_guidance_end = [control_guidance_end]

        if len(control_guidance_start) != len(control_guidance_end):
            raise ValueError(
                f"`control_guidance_start` has {len(control_guidance_start)} elements, but `control_guidance_end` has {len(control_guidance_end)} elements. Make sure to provide the same number of elements to each list."
            )

        if isinstance(self.controlnet, MultiControlRevampNetModel):
            if len(control_guidance_start) != len(self.controlnet.nets):
                raise ValueError(
                    f"`control_guidance_start`: {control_guidance_start} has {len(control_guidance_start)} elements but there are {len(self.controlnet.nets)} controlnets available. Make sure to provide {len(self.controlnet.nets)}."
                )

        for start, end in zip(control_guidance_start, control_guidance_end):
            if start >= end:
                raise ValueError(
                    f"control guidance start: {start} cannot be larger or equal to control guidance end: {end}."
                )
            if start < 0.0:
                raise ValueError(f"control guidance start: {start} can't be smaller than 0.")
            if end > 1.0:
                raise ValueError(f"control guidance end: {end} can't be larger than 1.0.")

    # 检查图像
    # 图像必须是 PIL tensor numpu 或者对应的list类型
    def check_image(self, image, prompt, prompt_embeds):
        image_is_pil = isinstance(image, PIL.Image.Image)
        image_is_tensor = isinstance(image, torch.Tensor)
        image_is_np = isinstance(image, np.ndarray)
        image_is_pil_list = isinstance(image, list) and isinstance(image[0], PIL.Image.Image)
        image_is_tensor_list = isinstance(image, list) and isinstance(image[0], torch.Tensor)
        image_is_np_list = isinstance(image, list) and isinstance(image[0], np.ndarray)

        if (
                not image_is_pil
                and not image_is_tensor
                and not image_is_np
                and not image_is_pil_list
                and not image_is_tensor_list
                and not image_is_np_list
        ):
            raise TypeError(
                f"image must be passed and be one of PIL image, numpy array, torch tensor, list of PIL images, list of numpy arrays or list of torch tensors, but is {type(image)}"
            )

        if image_is_pil:
            image_batch_size = 1
        else:
            image_batch_size = len(image)

        if prompt is not None and isinstance(prompt, str):
            prompt_batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            prompt_batch_size = len(prompt)
        elif prompt_embeds is not None:
            prompt_batch_size = prompt_embeds.shape[0]

        # if image_batch_size != 1 and image_batch_size != prompt_batch_size:
        #     raise ValueError(
        #         f"If image batch size is not 1, image batch size must be same as prompt batch size. image batch size: {image_batch_size}, prompt batch size: {prompt_batch_size}"
        #     )

    # 预处理图像
    def prepare_image(
            self,
            image,
            width,
            height,
            batch_size,
            num_images_per_prompt,
            device,
            dtype,
            do_classifier_free_guidance=False,
            guess_mode=False,
    ):
        image = self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32)
        image_batch_size = image.shape[0]

        if image_batch_size == 1:
            repeat_by = batch_size
        else:
            # image batch size is the same as prompt batch size
            repeat_by = num_images_per_prompt

        image = image.repeat_interleave(repeat_by, dim=0)

        image = image.to(device=device, dtype=dtype)

        if do_classifier_free_guidance and not guess_mode:
            image = torch.cat([image] * 2)

        return image

    # Copied from diffusers.pipelines.stable_diffusion.pipeline_stable_diffusion.StableDiffusionPipeline.prepare_latents
    """
    这段代码是一个函数 prepare_latents 的实现，它的作用是为生成模型（如 Stable Diffusion）准备初始潜变量（latents），这些潜变量是生成图像的起点。以下是对代码的详细中文解释：
函数参数

    batch_size：批量大小，表示一次生成多少张图像。
    num_channels_latents：潜变量的通道数，通常是生成模型中潜空间的维度。
    height：生成图像的期望高度。
    width：生成图像的期望宽度。
    dtype：潜变量的数据类型（如 torch.float32 或 torch.float16）。
    device：运行设备（如 "cuda" 或 "cpu"）。
    generator：随机数生成器，用于生成初始噪声。可以是 torch.Generator 或一个生成器列表。
    latents：可选参数，表示预定义的潜变量。如果提供，则直接使用这些潜变量，否则生成新的潜变量。

函数功能

    确定潜变量的形状：
        根据输入参数计算潜变量的形状。由于 Stable Diffusion 中的 VAE（变分自编码器）会对图像进行下采样，因此潜变量的高度和宽度会除以 vae_scale_factor。例如，如果 vae_scale_factor 是 8，那么潜变量的高度和宽度会缩小 8 倍。
        如果没有 VAE 下采样，潜变量的形状可以直接用 (batch_size, num_channels_latents, height, width)。
    检查生成器的批量大小：
        如果 generator 是一个生成器列表，且列表长度与 batch_size 不匹配，会抛出一个 ValueError。这是因为每个生成器实例通常对应一个独立的随机种子，批量大小必须与生成器数量一致。
    生成或调整潜变量：
        如果没有提供 latents，则使用 randn_tensor 函数生成随机噪声，其形状为 (batch_size, num_channels_latents, height // vae_scale_factor, width // vae_scale_factor)。
        如果提供了 latents，则将其移动到指定的设备（device）上。
    调整初始噪声的尺度：
        将生成的潜变量乘以调度器（scheduler）的初始噪声标准差（init_noise_sigma）。这是为了确保初始噪声的尺度符合调度器的要求，从而在生成过程中正确地调整噪声的强度。
    返回潜变量：
        返回调整后的潜变量 latents，这些潜变量将作为生成模型的输入。

总结
这段代码的作用是为生成模型准备初始潜变量。它根据输入参数计算潜变量的形状，生成或调整潜变量，并将其调整到合适的尺度。这些潜变量是生成图像的起点，后续会被用于扩散模型的逆向扩散过程。
    """

    def prepare_latents(self, batch_size, num_channels_latents, height, width, dtype, device, generator, latents=None):
        shape = (batch_size, num_channels_latents, height // self.vae_scale_factor, width // self.vae_scale_factor)
        # shape = (batch_size, num_channels_latents, height, width)
        if isinstance(generator, list) and len(generator) != batch_size:
            raise ValueError(
                f"You have passed a list of generators of length {len(generator)}, but requested an effective batch"
                f" size of {batch_size}. Make sure the batch size matches the length of the generators."
            )
        # 如果没有传入就随机生成一个 如果传入就使用传入的 latents
        if latents is None:
            latents = randn_tensor(shape, generator=generator, device=device, dtype=dtype)
        else:
            latents = latents.to(device)

        # scale the initial noise by the standard deviation required by the scheduler
        latents = latents * self.scheduler.init_noise_sigma
        return latents

    # 计算光流
    def compute_flows(self, of_model, images, rescale_factor=1):
        print('Computing forward and backward flows...')
        forward_flows, backward_flows = [], []
        for i in range(1, len(images)):
            prev_image = images[i - 1]  # 前一张图像
            cur_image = images[i]  # 当前图像
            fflow = of.get_flow(of_model, cur_image, prev_image, rescale_factor=rescale_factor)  # 前向光流估计
            bflow = of.get_flow(of_model, prev_image, cur_image, rescale_factor=rescale_factor)  # 后向光流估计
            forward_flows.append(fflow)
            backward_flows.append(bflow)
        backward_flows.reverse()
        return forward_flows, backward_flows

    # 程序执行处
    '''
    这段代码是一个生成图像的管道（pipeline）的调用函数的文档注释，它详细描述了函数的参数、功能和返回值。以下是对这段注释的中文解析：
    函数功能
    该函数是一个用于生成图像的管道调用函数，支持通过文本提示（prompt）或条件图像（image）来指导图像生成。它结合了文本到图像生成和条件图像生成的功能，并支持使用ControlNet来提供额外的生成指导。
    参数说明
    输入参数
        prompt (str 或 List[str]，可选)：用于指导图像生成的文本提示或提示列表。如果不提供，则需要传递prompt_embeds。
        image：用于指导生成的条件图像，可以是torch.FloatTensor、PIL.Image.Image、np.ndarray等格式。如果指定了多个ControlNet，则需要以列表形式传递图像。
        height 和 width (int，可选)：生成图像的高度和宽度，默认为模型配置的大小。
        num_inference_steps (int，可选，默认为50)：去噪步骤的数量。更多的去噪步骤通常会生成更高质量的图像，但会增加推理时间。
        guidance_scale (float，可选，默认为7.5)：更高的指导尺度值会鼓励模型生成与文本提示更紧密相关的图像，但可能会降低图像质量。当guidance_scale > 1时启用。
        negative_prompt (str 或 List[str]，可选)：用于指导生成中不包含的内容的提示或提示列表。如果不使用指导（guidance_scale < 1），则忽略此参数。
        num_images_per_prompt (int，可选，默认为1)：每个提示生成的图像数量。
        eta (float，可选，默认为0.0)：来自DDIM论文的参数η，仅适用于DDIMScheduler，在其他调度器中被忽略。
        generator (torch.Generator 或 List[torch.Generator]，可选)：用于使生成过程确定性的随机数生成器。
        latents (torch.FloatTensor，可选)：预生成的噪声潜变量，用于图像生成。如果不提供，则使用generator生成。
        prompt_embeds 和 negative_prompt_embeds (torch.FloatTensor，可选)：预生成的文本嵌入，用于调整文本输入（提示权重）。
        output_type (str，可选，默认为"pil")：生成图像的输出格式，可选择PIL.Image或np.array。
        return_dict (bool，可选，默认为True)：是否返回一个StableDiffusionPipelineOutput对象，而不是一个普通的元组。
        callback (Callable，可选)：在推理过程中每callback_steps步调用的函数。
        callback_steps (int，可选，默认为1)：调用callback函数的频率。
        cross_attention_kwargs (dict，可选)：传递给AttentionProcessor的参数字典。
        controlnet_conditioning_scale (float 或 List[float]，可选，默认为1.0)：ControlNet的输出在加入原始UNet的残差之前，会乘以这个比例因子。
        guess_mode (bool，可选，默认为False）：即使移除所有提示，ControlNet编码器也会尝试识别输入图像的内容。推荐使用3.0到5.0之间的guidance_scale值。
        control_guidance_start 和 control_guidance_end (float 或 List[float]，可选)：ControlNet开始和停止应用的总步数的百分比，默认为0.0和1.0。
    返回值
        如果return_dict为True，则返回一个StableDiffusionPipelineOutput对象；否则返回一个元组，其中第一个元素是生成的图像列表，第二个元素是一个布尔值列表，指示对应的生成图像是否包含“不适合工作场合”（nsfw）的内容。
    示例
    文档中未提供具体示例代码，但可以根据参数说明构建调用代码。例如：
    from diffusers import StableDiffusionPipeline
    import torch

    pipe = StableDiffusionPipeline.from_pretrained("model_name_or_path")
    prompt = "A beautiful landscape with mountains and a lake"
    image = pipe(prompt, num_inference_steps=50, guidance_scale=7.5).images[0]
    image.save("generated_image.png")

    注意事项

        文档中提到的DDIMScheduler和ControlNet是与生成过程相关的特定组件，需要根据具体使用的模型和库进行配置。
        参数eta仅在使用DDIMScheduler时生效，其他调度器会忽略该参数。
        controlnet_conditioning_scale和guess_mode等参数与ControlNet的使用相关，如果不使用ControlNet，则这些参数可以忽略或保持默认值。
    '''

    @torch.no_grad()
    @replace_example_docstring(EXAMPLE_DOC_STRING)
    def __call__(
            self,
            prompt: Union[str, List[str]] = None,
            images: PipelineImageInput = None,
            height: Optional[int] = None,
            width: Optional[int] = None,
            num_inference_steps: int = 50,
            guidance_scale: float = 7.5,
            negative_prompt: Optional[Union[str, List[str]]] = None,
            num_images_per_prompt: Optional[int] = 1,
            eta: float = 0.0,
            generator: Optional[Union[torch.Generator, List[torch.Generator]]] = None,
            latents: Optional[torch.FloatTensor] = None,
            prompt_embeds: Optional[torch.FloatTensor] = None,
            negative_prompt_embeds: Optional[torch.FloatTensor] = None,
            output_type: Optional[str] = "pil",
            return_dict: bool = True,
            callback: Optional[Callable[[int, int, torch.FloatTensor], None]] = None,
            callback_steps: int = 1,
            cross_attention_kwargs: Optional[Dict[str, Any]] = None,
            controlnet_conditioning_scale: Union[float, List[float]] = 1.0,
            guess_mode: bool = False,
            control_guidance_start: Union[float, List[float]] = 0.0,
            control_guidance_end: Union[float, List[float]] = 1.0,
            of_model=None,
            of_rescale_factor: int = 1,
            timesteps_to_be_used: Optional[List[float]] = None,
            GT_images: PipelineImageInput = None,
            lambda_step: int = 20,
            isMax = False,
            isDebugProcess = False
    ):
        r"""
        The call function to the pipeline for generation.

        Args:
            prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide image generation. If not defined, you need to pass `prompt_embeds`.
            image (`torch.FloatTensor`, `PIL.Image.Image`, `np.ndarray`, `List[torch.FloatTensor]`, `List[PIL.Image.Image]`, `List[np.ndarray]`,:
                    `List[List[torch.FloatTensor]]`, `List[List[np.ndarray]]` or `List[List[PIL.Image.Image]]`):
                The ControlNet input condition to provide guidance to the `unet` for generation. If the type is
                specified as `torch.FloatTensor`, it is passed to ControlNet as is. `PIL.Image.Image` can also be
                accepted as an image. The dimensions of the output image defaults to `image`'s dimensions. If height
                and/or width are passed, `image` is resized accordingly. If multiple ControlNets are specified in
                `init`, images must be passed as a list such that each element of the list can be correctly batched for
                input to a single ControlNet.
            height (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The height in pixels of the generated image.
            width (`int`, *optional*, defaults to `self.unet.config.sample_size * self.vae_scale_factor`):
                The width in pixels of the generated image.
            num_inference_steps (`int`, *optional*, defaults to 50):
                The number of denoising steps. More denoising steps usually lead to a higher quality image at the
                expense of slower inference.
            guidance_scale (`float`, *optional*, defaults to 7.5):
                A higher guidance scale value encourages the model to generate images closely linked to the text
                `prompt` at the expense of lower image quality. Guidance scale is enabled when `guidance_scale > 1`.
            negative_prompt (`str` or `List[str]`, *optional*):
                The prompt or prompts to guide what to not include in image generation. If not defined, you need to
                pass `negative_prompt_embeds` instead. Ignored when not using guidance (`guidance_scale < 1`).
            num_images_per_prompt (`int`, *optional*, defaults to 1):
                The number of images to generate per prompt.
            eta (`float`, *optional*, defaults to 0.0):
                Corresponds to parameter eta (η) from the [DDIM](https://arxiv.org/abs/2010.02502) paper. Only applies
                to the [`~schedulers.DDIMScheduler`], and is ignored in other schedulers.
            generator (`torch.Generator` or `List[torch.Generator]`, *optional*):
                A [`torch.Generator`](https://pytorch.org/docs/stable/generated/torch.Generator.html) to make
                generation deterministic.
            latents (`torch.FloatTensor`, *optional*):
                Pre-generated noisy latents sampled from a Gaussian distribution, to be used as inputs for image
                generation. Can be used to tweak the same generation with different prompts. If not provided, a latents
                tensor is generated by sampling using the supplied random `generator`.
            prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated text embeddings. Can be used to easily tweak text inputs (prompt weighting). If not
                provided, text embeddings are generated from the `prompt` input argument.
            negative_prompt_embeds (`torch.FloatTensor`, *optional*):
                Pre-generated negative text embeddings. Can be used to easily tweak text inputs (prompt weighting). If
                not provided, `negative_prompt_embeds` are generated from the `negative_prompt` input argument.
            output_type (`str`, *optional*, defaults to `"pil"`):
                The output format of the generated image. Choose between `PIL.Image` or `np.array`.
            return_dict (`bool`, *optional*, defaults to `True`):
                Whether or not to return a [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] instead of a
                plain tuple.
            callback (`Callable`, *optional*):
                A function that calls every `callback_steps` steps during inference. The function is called with the
                following arguments: `callback(step: int, timestep: int, latents: torch.FloatTensor)`.
            callback_steps (`int`, *optional*, defaults to 1):
                The frequency at which the `callback` function is called. If not specified, the callback is called at
                every step.
            cross_attention_kwargs (`dict`, *optional*):
                A kwargs dictionary that if specified is passed along to the [`AttentionProcessor`] as defined in
                [`self.processor`](https://github.com/huggingface/diffusers/blob/main/src/diffusers/models/attention_processor.py).
            controlnet_conditioning_scale (`float` or `List[float]`, *optional*, defaults to 1.0):
                The outputs of the ControlNet are multiplied by `controlnet_conditioning_scale` before they are added
                to the residual in the original `unet`. If multiple ControlNets are specified in `init`, you can set
                the corresponding scale as a list.
            guess_mode (`bool`, *optional*, defaults to `False`):
                The ControlNet encoder tries to recognize the content of the input image even if you remove all
                prompts. A `guidance_scale` value between 3.0 and 5.0 is recommended.
            control_guidance_start (`float` or `List[float]`, *optional*, defaults to 0.0):
                The percentage of total steps at which the ControlNet starts applying.
            control_guidance_end (`float` or `List[float]`, *optional*, defaults to 1.0):
                The percentage of total steps at which the ControlNet stops applying.

        Examples:

        Returns:
            [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] or `tuple`:
                If `return_dict` is `True`, [`~pipelines.stable_diffusion.StableDiffusionPipelineOutput`] is returned,
                otherwise a `tuple` is returned where the first element is a list with the generated images and the
                second element is a list of `bool`s indicating whether the corresponding generated image contains
                "not-safe-for-work" (nsfw) content.
        """
        #
        controlnet = self.controlnet._orig_mod if is_compiled_module(self.controlnet) else self.controlnet

        # align format for control guidance
        if not isinstance(control_guidance_start, list) and isinstance(control_guidance_end, list):
            control_guidance_start = len(control_guidance_end) * [control_guidance_start]
        elif not isinstance(control_guidance_end, list) and isinstance(control_guidance_start, list):
            control_guidance_end = len(control_guidance_start) * [control_guidance_end]
        elif not isinstance(control_guidance_start, list) and not isinstance(control_guidance_end, list):
            mult = len(controlnet.nets) if isinstance(controlnet, MultiControlNetModel) else 1
            control_guidance_start, control_guidance_end = mult * [control_guidance_start], mult * [
                control_guidance_end
            ]

        # 1. Check inputs. Raise error if not correct
        self.check_inputs(
            prompt,
            images,
            callback_steps,
            negative_prompt,
            prompt_embeds,
            negative_prompt_embeds,
            controlnet_conditioning_scale,
            control_guidance_start,
            control_guidance_end,
        )

        # 2. Define call parameters
        if prompt is not None and isinstance(prompt, str):
            batch_size = 1
        elif prompt is not None and isinstance(prompt, list):
            batch_size = len(prompt)
        else:
            batch_size = prompt_embeds.shape[0]
        # 确定执行设备
        device = self._execution_device
        # here `guidance_scale` is defined analog to the guidance weight `w` of equation (2)
        # of the Imagen paper: https://arxiv.org/pdf/2205.11487.pdf . `guidance_scale = 1`
        # corresponds to doing no classifier free guidance.
        do_classifier_free_guidance = guidance_scale > 1.0  # guidance_scale == 0.0  该项逻辑值为False

        if isinstance(controlnet, MultiControlRevampNetModel) and isinstance(controlnet_conditioning_scale, float):
            controlnet_conditioning_scale = [controlnet_conditioning_scale] * len(controlnet.nets)

        global_pool_conditions = (
            controlnet.config.global_pool_conditions
            if isinstance(controlnet, ControlRevampNetModel)
            else controlnet.nets[0].config.global_pool_conditions
        )
        guess_mode = guess_mode or global_pool_conditions

        # 3. Encode input prompt
        text_encoder_lora_scale = (
            cross_attention_kwargs.get("scale", None) if cross_attention_kwargs is not None else None
        )
        # 对输入的提示进行编码
        prompt_embeds, negative_prompt_embeds = self.encode_prompt(
            prompt,
            device,
            num_images_per_prompt,
            do_classifier_free_guidance,
            negative_prompt,
            prompt_embeds=prompt_embeds,
            negative_prompt_embeds=negative_prompt_embeds,
            lora_scale=text_encoder_lora_scale,
        )
        # For classifier free guidance, we need to do two forward passes.
        # Here we concatenate the unconditional and text embeddings into a single batch
        # to avoid doing two forward passes
        if do_classifier_free_guidance:
            prompt_embeds = torch.cat([negative_prompt_embeds, prompt_embeds])

        # 4. Prepare image
        # 预处理图像 对低分辨率图像进行处理上采样
        if isinstance(controlnet, ControlRevampNetModel):  # [180 320 3] 转变为 tensor 1 3 180 320
            images = [
                self.control_image_processor.preprocess(image, height=height, width=width).to(dtype=torch.float32).to(
                    device) for image in images]
            if GT_images is not None:
                GT_images = [
                    self.control_image_processor.preprocess(image, height=height, width=width).to(
                        dtype=torch.float32).to(
                        device) for image in GT_images]
            # 100 [1 3 180 320]
            # images_tensor = torch.stack(images,dim=1)
            # upscaled_images,_ = self.miavsr(images_tensor) # b f c h w --> b f c 4h 4w
            # upscaled_images = rearrange(upscaled_images, 'b f c h w -> f b c h w')
            # upscaled_images = list(upscaled_images)

            #利用双三次立方进行4倍上采样操作
            upscaled_images = [F.interpolate(image, scale_factor=4, mode='bicubic') for image in images]  # 1 3 720 1280

            height, width = upscaled_images[0].shape[-2:]  # 720 1280
        elif isinstance(controlnet, MultiControlRevampNetModel):
            images = []

            for image_ in image:
                image_ = self.prepare_image(
                    image=image_,
                    width=width,
                    height=height,
                    batch_size=batch_size * num_images_per_prompt,
                    num_images_per_prompt=num_images_per_prompt,
                    device=device,
                    dtype=controlnet.dtype,
                    do_classifier_free_guidance=do_classifier_free_guidance,
                    guess_mode=guess_mode,
                )

                images.append(image_)

            image = images
            height, width = image[0].shape[-2:]
        else:
            assert False

        # 5. Prepare timesteps       50步
        if timesteps_to_be_used is None:
            self.scheduler.set_timesteps(num_inference_steps, device=device)
        else:
            self.scheduler.set_timesteps(timesteps=timesteps_to_be_used, device=device)
        timesteps = self.scheduler.timesteps  # 步数时刻

        # 6. Prepare latent variables
        num_channels_latents = self.vae.config.latent_channels  # num_channel_latents  4
        latents = [self.prepare_latents(
            batch_size * num_images_per_prompt,
            num_channels_latents,
            height,
            width,
            prompt_embeds.dtype,
            device,
            generator
        ) for _ in range(len(images))]  # 1 3 180 320 -> 1 4 180 320  初始化 100 个随机噪声
        #初始噪声
        if isDebugProcess:
            model_pred_ori = [_.clone()  for _ in latents]    #原始的不参考之前的结果
            latent_predaa_ori = [_.clone() for _ in latents]  # 原始的不参考之前的结果
        # 模型预测 前一个预测结果
        # model_pred = [_.clone()  for _ in latents]  #  # 1 3 180 320 -> 1 4 180 320  初始化 100 个随机噪声
        model_pred = [None for _ in latents]
        latent_prev_Input = [None for _ in latents]

        noise_level = torch.cat([torch.tensor([20], dtype=torch.long, device=device)])
        # 7. Prepare extra step kwargs. TODO: Logic should ideally just be moved out of the pipeline
        extra_step_kwargs = self.prepare_extra_step_kwargs(generator, eta)

        # 7.1 Create tensor stating which controlnets to keep
        '''
        这段代码的作用是创建一个张量（controlnet_keep），用于指示在扩散模型的采样过程中，哪些时间步（timesteps）需要启用 ControlNet 模型。
        ControlNet 是一种用于控制生成过程的网络，通常用于在特定的时间范围内对生成结果进行引导。
        ControlNet 的范围为 0-1 之间 所以算的是归一化的步骤 对应两个状态 0或1 0是不启用 1 是启用
        '''
        controlnet_keep = []  # 控制net的启用状态 全为 1.0
        for i in range(len(timesteps)):
            keeps = [
                1.0 - float(i / len(timesteps) < s or (i + 1) / len(timesteps) > e)
                for s, e in zip(control_guidance_start, control_guidance_end)
            ]
            controlnet_keep.append(keeps[0] if isinstance(controlnet, ControlRevampNetModel) else keeps)

        # 8. Denoising loop  利用 raft 模型计算光流 100张上采样之后的图像
        forward_flows, backward_flows = self.compute_flows(of_model, upscaled_images, rescale_factor=of_rescale_factor)
        interp_mode = 'bilinear' if of_rescale_factor == 1 else 'nearest'  # 插值方式
        """
            这段代码实现了一个复杂的扩散模型采样过程，主要用于生成一系列图像（例如视频帧）。它结合了光流对齐、ControlNet 控制、双向采样（前向和后向）等技术，以生成高质量的动态内容。以下是代码的详细中文解释：
        代码功能

        初始化变量：
            num_warmup_steps：计算“预热步数”，用于控制进度条的更新。
            progress_bar：创建一个进度条，用于显示采样进度。
            reversed：布尔变量，用于控制双向采样的方向。
        双向采样循环：
            外层循环遍历所有时间步 timesteps。
            内层循环遍历所有图像 images，逐帧进行采样。
        光流对齐：
            根据 reversed 的值，选择前向光流（forward_flows）或后向光流（backward_flows）。
            对于非第一帧图像（num_image != 0），使用光流对齐技术将前一帧的估计结果（x0_est）对齐到当前帧。
        扩展潜变量：
            如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
            将潜变量与当前帧图像拼接，作为 UNet 的输入。
        ControlNet 推理：
            根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
            根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
            使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
        UNet 推理：
            使用 UNet 预测噪声残差（noise_pred）。
            如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
        更新潜变量：
            使用调度器（scheduler）的 step 方法，根据预测的噪声残差更新潜变量（latents）。
            获取更新后的潜变量（x_t-1）和估计的原始样本（x0_est）。
        进度条和回调函数：
            在每个时间步结束时更新进度条。
            如果提供了回调函数（callback），则在指定的步数间隔调用回调函数。
        双向采样：
            在完成一帧的采样后，反转所有图像、潜变量和上采样图像的顺序。
            切换 reversed 的值，以便在下一轮采样中使用相反方向的光流。
        关键技术点
        光流对齐：
            使用光流技术将前一帧的估计结果对齐到当前帧，确保生成的图像在时间上具有一致性。
        ControlNet：
            ControlNet 用于在生成过程中引入额外的控制信号，例如通过残差引导生成特定的纹理或风格。
        双向采样：
            通过前向和后向采样交替进行，提高生成结果的质量和一致性。
        分类器自由引导：
            通过无条件生成和条件生成的加权组合，实现对生成结果的精细控制。
        总结
            这段代码实现了一个复杂的扩散模型采样过程，适用于生成动态内容（如视频帧）。
            它结合了光流对齐、ControlNet 控制和双向采样等技术，能够在生成过程中实现高质量的时空一致性。
        """
        if lambda_step is None: # if user don't set lambda_step, then the default lambda_step = inference_step -1
            lambda_step = len(timesteps) - 1

        num_warmup_steps = len(timesteps) - num_inference_steps * self.scheduler.order  # 计算“预热步数”，用于控制进度条的更新
        with self.progress_bar(total=len(timesteps) * len(images)) as progress_bar:  # 创建一个进度条显示采样进度
            reversed = False  # 控制双向采样的方向

            #每一步预测的结果

            # for t, for image --> frame wise sampling
            len_images = len(images)     #一共有多少张影像
            for i, t in enumerate(timesteps):  # 双向循环  外层循环遍历时间步长 内层循环遍历 图像帧
                # 确定使用前向光流还是后向光流 100 张图像前向和后向 都是 99 个
                flows = forward_flows if not reversed else backward_flows

                # cur_idx = -1
                for num_image, data in enumerate(images):  # 遍历图像帧
                    image = data  # 图像数据

                    if isDebugProcess:
                        # compute Temporal Texture Guidance
                        # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                        if num_image != 0:  # if it's not the first image
                            x0_est_noprev = self.vae.decode(x0_est_noprev / self.vae.config.scaling_factor, return_dict=False)[
                                0]  # convert x0_est to RGB
                            warped_prev_est_noprev = of.flow_warp(x0_est_noprev, flows[num_image - 1],
                                                           interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                        # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                        # expand the latents if we are doing classifier free guidance
                        latent_model_input = torch.cat([latent_predaa_ori[num_image]] * 2) if do_classifier_free_guidance else \
                            latent_predaa_ori[num_image]

                        noisy_latents = latent_model_input

                        latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                        # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                        latent_model_input = torch.cat([latent_model_input, image], dim=1)
                        # latent_model_input = torch.cat([latent_model_input, image], dim=1)

                        # controlnet(s) inference
                        # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                        if guess_mode and do_classifier_free_guidance:
                            # Infer ControlNet only for the conditional batch.
                            control_model_input = latents
                            control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                            controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                        else:
                            control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                            controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                        # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                        if isinstance(controlnet_keep[i], list):
                            cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                        else:
                            controlnet_cond_scale = controlnet_conditioning_scale
                            if isinstance(controlnet_cond_scale, list):
                                controlnet_cond_scale = controlnet_cond_scale[0]
                            cond_scale = controlnet_cond_scale * controlnet_keep[i]

                        # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                        if num_image == 0:
                            # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                            down_block_res_samples = None
                            mid_block_res_sample = None
                        else:
                            # predict with Temporal Conditioning Module
                            down_block_res_samples, mid_block_res_sample = self.controlnet(
                                control_model_input,
                                t,
                                encoder_hidden_states=controlnet_prompt_embeds,
                                controlnet_cond=warped_prev_est_noprev,
                                conditioning_scale=cond_scale,
                                # class_labels = noise_level,
                                guess_mode=guess_mode,
                                return_dict=False,
                                timestep_cond=None
                            )

                            if guess_mode and do_classifier_free_guidance:
                                # Infered ControlNet only for the conditional batch.
                                # To apply the output of ControlNet to both the unconditional and conditional batches,
                                # add 0 to the unconditional batch to keep it unchanged.
                                down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                          down_block_res_samples]
                                mid_block_res_sample = torch.cat(
                                    [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                        # predict the noise residual
                        # 使用 UNet 预测噪声残差（noise_pred）。
                        # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                        noise_pred_prev = self.unet(
                            latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                            t,  # 当前的时间步 t
                            encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                            # class_labels = noise_level,
                            cross_attention_kwargs=cross_attention_kwargs,  # None
                            down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                            mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                            return_dict=False,
                        )[0]

                        # perform guidance
                        if do_classifier_free_guidance:
                            noise_pred_uncond, noise_pred_text = noise_pred_prev.chunk(2)
                            noise_pred_prev = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)
                        # model_ooori
                        output_prev = self.scheduler.step(noise_pred_prev, t, latent_predaa_ori[num_image], **extra_step_kwargs)
                        # 在这里更新 lantent
                        latnet_pred_prev, x0_est_noprev = output_prev.prev_sample, output_prev.pred_original_sample
                        #原始版本的结局
                        model_pred_ori[num_image] = noise_pred_prev
                        latent_predaa_ori[num_image] = latnet_pred_prev

                    # compute Temporal Texture Guidance
                    # 如果不是第一帧 根据图像估计的光流信息进行对齐，将前一帧的估计结果 x0_est 对齐到当前帧
                    if num_image != 0:  # if it's not the first image
                        x0_est = self.vae.decode(x0_est / self.vae.config.scaling_factor, return_dict=False)[
                            0]  # convert x0_est to RGB
                        warped_prev_est = of.flow_warp(x0_est, flows[num_image - 1],
                                                       interp_mode=interp_mode)  # warp it to current frame            #光流对齐
                    # 如果启用分类器自由引导（do_classifier_free_guidance），将潜变量扩展为两份（一份用于条件生成，一份用于无条件生成）。
                    # expand the latents if we are doing classifier free guidance
                    latent_model_input = torch.cat([latents[num_image]] * 2) if do_classifier_free_guidance else \
                    latents[num_image]

                    noisy_latents = latent_model_input

                    latent_model_input = self.scheduler.scale_model_input(latent_model_input, t)
                    # 将潜变量与当前帧图像拼接，作为 UNet 的输入。 潜变量 4 通道，image 3 通道 将latent与image拼接之后是 7 通道
                    latent_model_input = torch.cat([latent_model_input, image], dim=1)
                    # latent_model_input = torch.cat([latent_model_input, image], dim=1)

                    # controlnet(s) inference
                    # 根据 guess_mode 和 do_classifier_free_guidance 的值，决定是否仅对条件批次进行 ControlNet 推理。
                    if guess_mode and do_classifier_free_guidance:
                        # Infer ControlNet only for the conditional batch.
                        control_model_input = latents
                        control_model_input = self.scheduler.scale_model_input(control_model_input, t)
                        controlnet_prompt_embeds = prompt_embeds.chunk(2)[1]
                    else:
                        control_model_input = latent_model_input  # 拼接之后的 latent_model_input 7通道
                        controlnet_prompt_embeds = prompt_embeds  # prompt_embeds 文本编码的特征向量

                    # 根据 controlnet_keep 的值，动态调整 ControlNet 的条件缩放因子（cond_scale）。
                    if isinstance(controlnet_keep[i], list):
                        cond_scale = [c * s for c, s in zip(controlnet_conditioning_scale, controlnet_keep[i])]
                    else:
                        controlnet_cond_scale = controlnet_conditioning_scale
                        if isinstance(controlnet_cond_scale, list):
                            controlnet_cond_scale = controlnet_cond_scale[0]
                        cond_scale = controlnet_cond_scale * controlnet_keep[i]

                    # 使用 ControlNet 计算额外的残差（down_block_res_samples 和 mid_block_res_sample），用于引导生成过程。
                    if num_image == 0:
                        # predict without Temporal Conditioning Module   #第一张不使用 Temporal Conditioning Module
                        down_block_res_samples = None
                        mid_block_res_sample = None
                    else:
                        # predict with Temporal Conditioning Module
                        down_block_res_samples, mid_block_res_sample = self.controlnet(
                            control_model_input,
                            t,
                            encoder_hidden_states=controlnet_prompt_embeds,
                            controlnet_cond=warped_prev_est,
                            conditioning_scale=cond_scale,
                            # class_labels = noise_level,
                            guess_mode=guess_mode,
                            return_dict=False,
                            timestep_cond=None
                        )

                        if guess_mode and do_classifier_free_guidance:
                            # Infered ControlNet only for the conditional batch.
                            # To apply the output of ControlNet to both the unconditional and conditional batches,
                            # add 0 to the unconditional batch to keep it unchanged.
                            down_block_res_samples = [torch.cat([torch.zeros_like(d), d]) for d in
                                                      down_block_res_samples]
                            mid_block_res_sample = torch.cat(
                                [torch.zeros_like(mid_block_res_sample), mid_block_res_sample])

                    # predict the noise residual
                    # 使用 UNet 预测噪声残差（noise_pred）。
                    # 如果启用分类器自由引导，将无条件噪声预测和条件噪声预测进行加权组合。
                    noise_pred = self.unet(
                        latent_model_input,  # latent_model_input 7通道 将latent与image拼接之后是 7 通道
                        t,  # 当前的时间步 t
                        encoder_hidden_states=prompt_embeds,  # prompt_embeds 文本编码的特征向量
                        # class_labels = noise_level,
                        cross_attention_kwargs=cross_attention_kwargs,  # None
                        down_block_additional_residuals=down_block_res_samples,  # 残差列表 处理时间层
                        mid_block_additional_residual=mid_block_res_sample,  # 残差 处理中间层 时间处理
                        return_dict=False,
                    )[0]

                    # perform guidance
                    if do_classifier_free_guidance:
                        noise_pred_uncond, noise_pred_text = noise_pred.chunk(2)
                        noise_pred = noise_pred_uncond + guidance_scale * (noise_pred_text - noise_pred_uncond)



                    # if i > lambda_step:
                    #     model_pred_post = controlnet.revampnet(latent_model_input, noise_pred, t)
                    # else:
                    #     model_pred_post = noise_pred

                    # model_pred_post = noise_scheduler.get_velocity(x0_est, Eout_post, timesteps)

                    # # # compute the previous noisy sample x_t -> x_t-1
                    # x0_est = self.scheduler.get_approximated_x0(noise_pred, t, latents[num_image])
                    #
                    # # E_in = self.scheduler.get_noiseIn(latents[num_image], t, x0_est)
                    # E_out = self.scheduler.get_noiseOut(noise_pred, t, x0_est)
                    if i < lambda_step:
                        # output = self.scheduler.step(noise_pred, t, latents[num_image], **extra_step_kwargs)
                        # # 在这里更新 lantent
                        # latnet_pred_pr, x0_est_pr = output.prev_sample, output.pred_original_sample
                        # # model_pred_post = controlnet.revampnet(latents[num_image], noise_pred, t,isMax=isMax)
                        model_pre = model_pred[num_image]               #前一时刻的输出
                        lantent_previn = latent_prev_Input[num_image]   #前一时刻的输入
                        model_pred_post = noise_pred
                        # x0_est = self.scheduler.get_approximated_x0(noise_pred, t, latents[num_image])
                        if model_pre is not None:
                            model_pre = model_pred_post
                            output = self.scheduler.step(model_pred_post, t, latents[num_image], **extra_step_kwargs)
                            # 在这里更新 lantent
                            latnet_pred, x0_est = output.prev_sample, output.pred_original_sample

                            latnet_pred_post = self.controlnet.revampnet(latents[num_image], latnet_pred, t)
                            latents[num_image] = latnet_pred_post


                            # prev_t = self.scheduler.previous_timestep(t)
                            # #有前一个时刻
                            # # 得到一个近视的X0 getNormalVelocity
                            # model_pre_prevtimeNormal = self.scheduler.getNormalVelocity(model_pre,
                            #                                                               prev_t)
                            # model_predNormal = self.scheduler.getNormalVelocity(noise_pred, t)
                            # # 前一时刻噪声和当前时刻噪声的线性组合 仍然是一个正态分布
                            # epision = model_pre_prevtimeNormal - model_predNormal
                            # # 模型的输入是什么呢？需要得到两个权重参数和一个偏移参数 输入两个状态吧
                            # # noisy_latents_cat 与 noisy_latents_prev_cat 但是 还是需要和一个随机的噪声搭上关系 不一定直接new一个
                            # #
                            #
                            # epsilon_pred_post = self.controlnet.revampnet(model_pred_prevtime, model_pred, epision)
                            # # epsilon_pred_post = controlnet.revampnet(model_pred_prevtime, model_pred, t)
                            # # x0_est = noise_scheduler.get_approximated_x0(model_pred, timesteps,noisy_latents)
                            # # model_pred_post = noise_scheduler.get_velocity(x0_est, epsilon_pred_post, timesteps)  # 去噪的结果
                            # # model_pred_post = controlnet.revampnet(noisy_latents, model_pred, timesteps)
                            # # x0_est =  self.scheduler.get_approximated_x0(model_pred, t, noisy_latents)
                            # # model_pred_post =  self.scheduler.get_velocity(x0_est, epsilon_pred_post, t)
                            # #利用处理的噪声获取 lantent[num_image]
                            #
                            # output = self.scheduler.stepNoise(epsilon_pred_post, t, latents[num_image], **extra_step_kwargs)
                            # # 在这里更新 lantent
                            # latnet_pred, x0_est = output.prev_sample, output.pred_original_sample
                            # latents[num_image] = latnet_pred
                            # model_pred_post = noise_pred
                        else:
                            #第一帧 利用modelpost获取 lantent[num_image]
                            model_pre = model_pred_post
                            output = self.scheduler.step(model_pred_post, t, latents[num_image], **extra_step_kwargs)
                            # 在这里更新 lantent
                            latnet_pred, x0_est = output.prev_sample, output.pred_original_sample
                            latents[num_image] = latnet_pred
                            model_pred_post = noise_pred
                    else:
                        model_pre = noise_pred
                        model_pred_post = noise_pred
                        output = self.scheduler.step(model_pred_post, t, latents[num_image], **extra_step_kwargs)
                        # 在这里更新 lantent
                        latnet_pred, x0_est = output.prev_sample, output.pred_original_sample
                        latents[num_image] = latnet_pred

                    model_pred[num_image] = model_pred_post
                    latent_prev_Input[num_image] =  latent_model_input
